INSERT INTO `rule_judge_conclusion` VALUES ('c_add_betrothal_full','betrothal','可主张全额返还彩礼','满足彩礼给付与法定返还关键要件。','important','[\"law_1042\",\"law_jshj_5\"]','彩礼返还请求','全额返还支持可能性较高','建议重点提交彩礼支付凭证、未登记/困难证明材料。',1,'2026-04-09 13:22:06'),('c_add_betrothal_no_refund','betrothal','存在不返还抗辩空间','已登记并长期共同生活，不返还抗辩空间较大。','warning','[\"law_jshj_5\"]','抗辩方向','可主张不返还或少返还','建议提交共同生活事实与支出证据。',1,'2026-04-09 13:22:06'),('c_add_betrothal_partial','betrothal','可主张部分返还彩礼','存在已登记且共同生活较短等情形，倾向部分返还。','warning','[\"law_jshj_5\"]','彩礼返还请求','部分返还支持可能性较高','建议围绕共同生活时长和财产去向补强证据。',1,'2026-04-09 13:22:06'),('c_add_labor_injury_disability','labor_injury','伤残待遇主张有支持可能','已认定伤残且单位拒绝支付待遇。','important','[\"law_injury_37\"]','伤残待遇请求','可主张一次性伤残补助等','建议提交伤残等级结论与拒付证据。',1,'2026-04-09 13:22:06'),('c_add_labor_injury_medical','labor_injury','工伤医疗费用主张有支持可能','存在工伤医疗支出且已申请认定。','important','[\"law_injury_30\"]','医疗待遇请求','可主张工伤医疗费用','建议汇总票据、病历及支付记录。',1,'2026-04-09 13:22:06'),('c_add_labor_injury_recognition','labor_injury','工伤认定主张有支持可能','工伤认定核心前提基本具备。','important','[\"law_injury_14\"]','工伤认定请求','可优先推进工伤认定','建议尽快提交认定申请及事故材料。',1,'2026-04-09 13:22:06'),('c_add_overtime_holiday','labor_overtime','节假日加班费主张有支持可能','存在法定节假日加班且未足额支付。','important','[\"law_labor_44\"]','加班费请求','可主张节假日加班费','建议提交节假日值班及发薪对照材料。',1,'2026-04-09 13:22:06'),('c_add_overtime_restday','labor_overtime','休息日加班费主张有支持可能','存在休息日加班且未补休。','important','[\"law_labor_44\"]','加班费请求','可主张休息日加班费','建议提交排班与补休记录。',1,'2026-04-09 13:22:06'),('c_add_overtime_workday','labor_overtime','工作日加班费主张有支持可能','工作日延时加班事实与欠付事实较明确。','important','[\"law_labor_44\",\"law_contract_31\"]','加班费请求','可主张工作日加班费差额','建议按月整理工时和工资差额。',1,'2026-04-09 13:22:06'),('c_adoption_confirm_support','conclusion','收养确认存在支持路径','登记收养、事实收养长期维持、送养同意和抚养能力等事实可支持确认主张。','important','[\"law_1093\",\"law_1105\"]','收养确认支持路径','支持继续主张','整理登记材料、送养同意、照顾记录和收入居住材料。',1,'2026-04-16 15:49:26'),('c_adoption_de_facto_confirm','conclusion','收养确认中的事实收养路径较明确','虽未登记但长期共同生活、持续照顾和抚养能力较明确时，可围绕事实收养展开主张。','important','[\"law_1093\"]','事实收养路径','可围绕事实收养主张','重点整理共同生活、照顾记录和收入居住材料。',1,'2026-04-16 15:49:26'),('c_adoption_dissolve_support','conclusion','解除收养存在支持路径','解除原因、长期矛盾或不尽抚养义务等线索较明确，可进入解除收养审查。','important','[\"law_1115\"]','解除收养支持路径','支持继续主张','重点补强解除原因与解除后未成年人安排。',1,'2026-04-16 15:49:26'),('c_adoption_exception','conclusion','收养纠纷需先区分确认路径与解除路径','若登记、事实收养、解除原因与后续抚养安排混在一起，容易导致请求方向不清。','warning','[\"law_1093\",\"law_1115\"]','收养纠纷例外路径','需先校正主张方向','明确是确认收养还是解除收养，再分别补证。',1,'2026-04-16 15:49:26'),('c_adoption_initial','conclusion','收养关系可进入确认或解除审查','存在收养事实/登记且有证据补强时，可形成确认收养关系或解除收养关系的证据链。','important','[\"law_1084\"]','收养确认/解除审查入口','建议补强收养登记材料、照顾记录与解除原因线索。','如无登记，补强长期事实维持证据。',1,'2026-04-16 13:45:06'),('c_adoption_post_dissolve_arrangement','conclusion','解除收养后的未成年人安排需单独成型','解除收养后如未成年人监护、抚养费和生活安排未明确，后续执行性会明显不足。','important','[\"law_1115\",\"law_1084\"]','解除收养后果路径','需同步细化后续安排','整理监护、抚养费用和生活安置方案。',1,'2026-04-16 15:49:26'),('c_adoption_precondition','conclusion','收养关系纠纷已具备审查入口','已存在确认或解除收养的明确请求，可进入收养关系审查。','important','[\"law_1093\",\"law_1115\"]','收养纠纷前置','可进入实体分析','继续锁定收养路径类型及共同生活状态。',1,'2026-04-16 15:49:26'),('c_adoption_registered_confirm','conclusion','收养确认中的登记收养路径较明确','已办理收养登记且有送养同意、抚养能力材料时，确认收养关系路径更稳定。','important','[\"law_1093\",\"law_1105\"]','登记收养路径','优先围绕登记收养主张','重点整理登记材料、送养同意和资格材料。',1,'2026-04-16 15:49:26'),('c_child_support_change_amount','conclusion','抚养费：变更数额路径较明确','子女支出或收入能力发生变化、教育医疗等重大支出明确时，变更数额更有依据。','important','[\"law_1085\"]','变更请求','可主张提高/降低抚养费','建议提交支出变化与收入变化证据。',1,'2026-04-16 15:56:36'),('c_child_support_change_custody','conclusion','变更抚养关系：路径较明确','存在法定变更情形且有利于子女成长证据较充分时，变更抚养主张更有优势。','important','[\"law_1084\"]','变更抚养请求','可主张变更直接抚养','建议提交抚养现状、不利因素及子女意愿材料。',1,'2026-04-16 15:56:36'),('c_child_support_claim_fee','conclusion','抚养费：主张支付/补付路径较明确','对方未支付抚养费且基础文书或约定明确时，补付/持续支付主张更稳。','important','[\"law_1085\"]','抚养费请求','可主张支付/补付抚养费','建议固定拖欠记录、催要记录与对方收入能力证据。',1,'2026-04-16 15:56:36'),('c_child_support_precondition','conclusion','抚养费/变更抚养：具备审查入口','存在亲子关系与抚养费争议线索，可进入抚养费、拖欠补付或变更抚养的分支审查。','important','[\"law_1085\"]','审查入口','进入抚养纠纷分支分析','建议补齐亲子关系材料、既有协议/判决与支付记录。',1,'2026-04-16 15:56:36'),('c_cohabitation_contribution_ratio','conclusion','同居财产中的出资比例与共同购置路径较明确','共同购置房车或大额财物且一方明显高额出资时，更利于细化析产比例。','important','[\"law_308\",\"law_309\"]','同居出资比例路径','可细化财产份额方案','重点整理共同购置合同、出资流水和比例说明。',1,'2026-04-16 15:49:26'),('c_cohabitation_custody_support','conclusion','同居关系中的子女抚养安排可同步处理','存在子女、实际照料和费用承担争议时，可同步处理直接抚养与抚养费。','important','[\"law_1084\",\"law_1085\"]','同居子女路径','可同步主张抚养安排','整理出生材料、照料记录和月支出清单。',1,'2026-04-16 15:49:26'),('c_cohabitation_direct_custody','conclusion','同居子女中的直接抚养与月支出路径较明确','直接抚养主张、现有照料状态和孩子月支出清晰时，更利于形成抚养安排。','important','[\"law_1084\",\"law_1085\"]','同居直接抚养路径','可细化抚养方案','重点整理照料现状、支出清单和支付不足材料。',1,'2026-04-16 15:49:26'),('c_cohabitation_exception','conclusion','同居纠纷需避免财产和身份关系混同','若同居时间、共同投入或子女安排都不清晰，容易导致主张方向泛化。','warning','[\"law_1042\"]','同居关系例外路径','需先明确争点','先区分财产析产、子女抚养和一般返还请求。',1,'2026-04-16 15:49:26'),('c_cohabitation_initial','conclusion','同居关系财产与子女安排可进入裁判分析','同居投入与财产争议并存在抚养问题时，可组织财产析产与抚养费/照护安排证据补强。','important','[\"law_1087\",\"law_1084\"]','同居析产与抚养审查','建议补强同住证据、转账流水、孩子生活照护与支付拒绝线索。','围绕财产范围清晰与证据链条组织证成。',1,'2026-04-16 13:45:06'),('c_cohabitation_precondition','conclusion','同居关系纠纷已具备审查前提','已存在同居关系及财产或子女争议线索，可进入同居关系实体分析。','important','[\"law_1042\",\"law_1084\"]','同居关系前置','可进入实体分析','继续固定同居起止时间和共同投入情况。',1,'2026-04-16 15:49:26'),('c_cohabitation_property_support','conclusion','同居财产分割存在支持路径','共同生活、共同购置或一方明显出资较高时，可围绕共有投入主张析产。','important','[\"law_308\",\"law_309\"]','同居财产支持路径','支持继续主张','重点整理共同购置合同、转账流水和出资比例。',1,'2026-04-16 15:49:26'),('c_divorce_children_priority','divorce_property','分割时需重点照顾未成年子女利益','案件存在未成年子女长期照顾事实，分割时会强化居住稳定性考量。','important','[\"law_1084\"]','分割倾向','照顾子女利益因素显著','可重点提交抚养现状、学籍居住连续性等材料。',1,'2026-04-07 11:41:45'),('c_divorce_common_property','divorce_property','房产更可能被认定为夫妻共同财产','存在婚后取得、共同还贷或共有登记等共同财产特征。','important','[\"law_1062\",\"law_jsyi_25\",\"law_jsyi_27\"]','财产属性判断','共同财产倾向较高','可围绕分割比例、居住需求、还贷贡献提出具体分割方案。',1,'2026-04-07 11:41:45'),('c_divorce_compensation','divorce_property','可主张折价补偿或份额差异化分配','存在明显贡献差异或登记与还贷不一致情形，具备补偿主张空间。','important','[\"law_1087\",\"law_1088\"]','分割方案','可主张补偿/折价款','建议结合评估价、剩余贷款、历史出资形成可执行方案。',1,'2026-04-07 11:41:45'),('c_divorce_dispute_breakdown','conclusion','离婚纠纷：感情破裂路径较明确','分居、冲突、调解失败等事实更有利于支持“感情确已破裂”。','important','[\"law_1079\"]','离婚诉请','判决离婚支持度提升','建议按时间线整理分居/冲突/调解材料并固定证据。',1,'2026-04-16 15:56:36'),('c_divorce_dispute_custody','conclusion','离婚纠纷：子女抚养路径较明确','子女长期随一方生活、另一方存在不利因素或抚养能力对比明确时，抚养请求更有优势。','important','[\"law_1084\"]','抚养诉请','可主张直接抚养/抚养费/探望安排','建议提交就学、照护、收入住房与子女意愿（八周岁以上）材料。',1,'2026-04-16 15:56:36'),('c_divorce_dispute_need_more_facts','conclusion','离婚纠纷：当前事实不足需先补齐','离婚事由、子女或财产债务的关键事实未形成稳定证据链，易导致结论不稳或答非所问。','warning','[\"law_1079\"]','补强方向','先补齐关键事实再判断路径','建议优先补齐结婚登记、分居/冲突证据、子女抚养现状、财产债务清单。',1,'2026-04-16 15:56:36'),('c_divorce_dispute_precondition','conclusion','离婚纠纷：具备审查入口','存在合法婚姻关系并已提出离婚主张线索，可进入离婚事由/子女/财产债务的分支审查。','important','[\"law_1079\"]','审查入口','进入离婚纠纷分支分析','建议补齐结婚登记、感情破裂、子女与财产债务线索。',1,'2026-04-16 15:56:36'),('c_divorce_dispute_property_debt','conclusion','离婚纠纷：财产与债务处理路径较明确','共同财产/共同债务范围越清晰，越利于一次性解决争议。','important','[\"law_1087\",\"law_1089\"]','财产债务诉请','建议同步提出财产债务处理','建议形成资产负债清单并逐项对应证据。',1,'2026-04-16 15:56:36'),('c_divorce_dispute_violence_fault','conclusion','离婚纠纷：家暴/重大过错路径较明确','家暴或重大过错线索清晰时，离婚支持度与衍生请求基础更强。','important','[\"law_1091\",\"law_1079\"]','离婚诉请','可优先走家暴/过错证据链','建议固定报警回执、告诫书、伤情、就医记录等。',1,'2026-04-16 15:56:36'),('c_divorce_personal_property','divorce_property','房产更可能被认定为一方个人财产','现有事实显示房产取得时间或赠与方式倾向个人财产属性。','warning','[\"law_1063\",\"law_jsyi_26\"]','财产属性判断','个人财产倾向较高','需重点核查婚后增值、共同还贷与产权变动对分割的影响。',1,'2026-04-07 11:41:45'),('c_divorce_precondition','divorce_property','满足离婚房产分割审查前提','已形成合法婚姻关系、离婚状态与房产争议三项基础。','important','[\"law_1062\"]','审查入口','可进入房产分割裁判分析','建议继续补充产权、出资、还贷、子女抚养等证据。',1,'2026-04-07 11:41:45'),('c_family_partition_exception','conclusion','分家析产需先澄清成员范围与财产边界','若成员范围、是否已实际分家或财产登记名义不清，易导致析产请求泛化。','warning','[\"law_308\"]','分家析产例外路径','需先补强基础事实','先明确家庭成员、分家状态和占有使用事实。',1,'2026-04-16 15:49:26'),('c_family_partition_initial','conclusion','分家析产可进入财产范围与分割证据审查','同堂共同生活并存在财产争议时，可组织共同财产范围认定与析产分割证成。','important','[\"law_1087\",\"law_1092\"]','析产分割审查入口','建议补强财产清单/账本、登记证据与资金来源。','如存在转移/不当处分，补强对应流水与沟通证据。',1,'2026-04-16 13:45:06'),('c_family_partition_member_boundary','conclusion','分家析产中的成员范围与分家状态路径较明确','家庭成员范围、是否已实际分家和长期占有使用状态明确时，更利于确认析产边界。','important','[\"law_308\"]','分家析产成员边界路径','可细化析产边界','重点整理成员清单、分家证明和占有使用材料。',1,'2026-04-16 15:49:26'),('c_family_partition_precondition','conclusion','分家析产纠纷已具备审查入口','共同生活、共同置办财产和析产请求已形成基础，能够进入析产审查。','important','[\"law_308\",\"law_309\"]','分家析产前置','可进入实体分析','继续明确家庭成员范围、登记名义和出资来源。',1,'2026-04-16 15:49:26'),('c_family_partition_registration_source','conclusion','分家析产中的登记名义与出资来源路径较明确','登记名义、权属材料和主要出资来源较清晰时，更利于细化权利份额。','important','[\"law_309\"]','分家析产权属来源路径','可细化份额主张','重点整理权属证明、转账流水和出资来源材料。',1,'2026-04-16 15:49:26'),('c_family_partition_support','conclusion','分家析产主张存在支持路径','财产范围、登记名义、长期占有使用和主要出资来源较清晰时，可进一步主张析产分割。','important','[\"law_308\",\"law_309\"]','分家析产支持路径','支持继续主张','整理财产清单、账本、登记和出资材料。',1,'2026-04-16 15:49:26'),('c_guardianship_care_ability','conclusion','监护申请人的照护能力路径较明确','照护能力、稳定居住和财产管理需求较明确时，更利于形成可执行的监护方案。','important','[\"law_31\",\"law_35\"]','监护照护能力路径','可继续补强监护适格性','整理收入、居住、照护安排和财产管理材料。',1,'2026-04-16 15:49:26'),('c_guardianship_initial','conclusion','监护权指定/变更可进入实体审查','被监护人无/限制能力与医学鉴定证据具备时，可形成指定/变更监护人请求。','important','[\"law_1084\"]','监护权审查入口','建议补强鉴定/诊断证据与申请文书材料。','如现任监护不适合或不履行，补强对应事实证据。',1,'2026-04-16 13:45:06'),('c_guardianship_precondition','conclusion','监护权纠纷已具备审查入口','被监护人能力状态和监护请求已基本明确，可进入指定或变更监护人审查。','important','[\"law_27\",\"law_31\"]','监护权前置','可进入实体分析','继续核查主体资格、照护能力和基层组织意见。',1,'2026-04-16 15:49:26'),('c_guardianship_property_support','conclusion','监护事项可延伸至财产管理保护路径','若被监护人同时存在财产管理需求，应同步考虑监护范围与财产保护安排。','important','[\"law_35\"]','监护财产路径','可同步主张财产管理','整理财产清单、保管风险和管理需求说明。',1,'2026-04-16 15:49:26'),('c_guardianship_subject_qualification','conclusion','监护申请人的主体资格路径较明确','申请人顺位、亲属关系和基层组织意见较清晰时，指定或变更监护人的主体基础更稳。','important','[\"law_27\"]','监护主体资格路径','优先围绕主体资格主张','重点整理身份顺位、亲属关系和基层意见材料。',1,'2026-04-16 15:49:26'),('c_guardianship_support','conclusion','监护权指定或变更存在支持路径','申请人主体资格、照护能力和现任监护缺位或不适合情形较明确。','important','[\"law_27\",\"law_31\"]','监护权支持路径','支持继续主张','补强诊断鉴定、照护条件和基层组织意见。',1,'2026-04-16 15:49:26'),('c_in_marriage_property_division_initial','conclusion','婚内夫妻财产分割可进入裁判分析','存在婚内共同财产争议及证据线索时，可进入实体审查并形成分割/处置方案。','important','[\"law_1087\",\"law_1092\"]','婚内财产分割','建议继续补强藏匿转移、挥霍处置与医疗紧急支出证据。','围绕范围清晰与交易/登记证据组织证成。',1,'2026-04-16 13:45:06'),('c_in_marriage_property_exception','conclusion','婚内财产分割需先补强范围与紧迫性','目前仅有一般争议线索，若共同财产范围或紧迫处分理由不清，容易导致请求泛化。','warning','[\"law_1087\"]','婚内财产分割例外路径','需先补强再主张','补充财产清单、争议财产类型及对家庭生活影响。',1,'2026-04-16 15:49:26'),('c_in_marriage_property_livelihood_impact','conclusion','婚内财产分割中的基本生活受影响路径较明确','重大医疗、挥霍处置已影响家庭基本生活时，紧迫性和保护必要性更强。','important','[\"law_1087\",\"law_1092\"]','婚内财产生活影响路径','可强化紧迫性主张','整理医疗支出、家庭欠费和生活受影响材料。',1,'2026-04-16 15:49:26'),('c_in_marriage_property_precondition','conclusion','婚内财产分割已具备审查前提','婚姻关系存续且已出现婚内共同财产争议，可进入婚内析产审查。','important','[\"law_1087\",\"law_1092\"]','婚内财产分割前置','可进入实体分析','继续围绕共同财产范围、转移方式和支出影响补强。',1,'2026-04-16 15:49:26'),('c_in_marriage_property_support','conclusion','婚内财产分割主张存在支持路径','存在藏匿转移、挥霍或重大医疗紧急需求等情形，具备请求分割或采取保护措施的空间。','important','[\"law_1087\",\"law_1092\"]','婚内财产分割支持路径','支持继续主张','重点固定共同财产范围、转账流水、医疗票据与挥霍细节。',1,'2026-04-16 15:49:26'),('c_in_marriage_property_type_scope','conclusion','婚内财产分割中的财产类型与范围路径较明确','争议财产类型、范围边界和转移方式较明确时，更利于形成具体分割请求。','important','[\"law_1087\",\"law_1092\"]','婚内财产范围路径','可细化分割标的','重点整理房产、账户、股权等类型及财产清单。',1,'2026-04-16 15:49:26'),('c_inherit_share','conclusion','可主张确认继承份额','继承开始且遗产线索存在时，可主张确认继承人及份额并分割。','success','[\"law_1127\",\"law_1130\"]','确认继承份额','可主张确认并分割','围绕继承人范围、遗产清单、份额证据',1,'2026-04-14 16:29:27'),('c_inherit_will_dispute','conclusion','存在遗嘱效力争议处理空间','存在遗嘱且有形式/意思表示瑕疵线索时，可主张确认遗嘱效力或撤销。','warning','[\"law_1133\"]','遗嘱效力争议','可主张确认/撤销','围绕遗嘱形式、见证、鉴定等举证',1,'2026-04-14 16:29:27'),('c_labor_no_contract_double','labor_contract','可主张未签书面劳动合同期间双倍工资','入职超过一个月未签劳动合同且有工资支付事实支持。','important','[\"law_contract_10\",\"law_contract_82\"]','双倍工资请求','可主张（符合法定要件）','建议按入职时间线整理证据，核算可主张区间后通过劳动仲裁主张。',1,'2026-04-07 11:41:34'),('c_labor_no_contract_open_term','labor_contract','无固定期限合同请求有支持可能','已明确主张且满足法定条件。','important','[\"law_contract_14\"]','无固定期限合同请求','可主张','建议提交工龄、续签记录等证明满足法定条件。',1,'2026-04-07 11:41:34'),('c_labor_no_contract_sign','labor_contract','可请求单位补签书面劳动合同','劳动关系存续且未签书面合同，补签请求具有正当性。','important','[\"law_contract_10\"]','补签劳动合同请求','可主张','建议先发出书面补签申请并保留送达凭证。',1,'2026-04-07 11:41:34'),('c_labor_termination_illegal','labor_termination','解除行为存在较高概率被认定为违法','解除理由或程序不符合法定要求，或存在特殊保护期内解除风险。','important','[\"law_contract_39\",\"law_contract_40\",\"law_contract_41\",\"law_contract_48\",\"law_contract_87\"]','违法解除判断','可优先主张认定为违法解除','建议围绕解除理由合法性、解除程序合法性、特殊保护期事实整理证据。',1,'2026-04-07 11:41:34'),('c_labor_termination_reinstate','labor_termination','可请求继续履行劳动合同','劳动者已明确提出恢复劳动关系请求。','important','[\"law_contract_48\"]','诉请方向','可请求继续履行劳动合同','如劳动者主张继续履行且用人单位仍可继续履行，可作为主要请求。',1,'2026-04-07 11:41:34'),('c_labor_termination_wage_gap','labor_termination','可主张停工期间工资损失','劳动者已明确提出停工期间工资损失请求。','important','[\"law_contract_87\"]','诉请方向','可主张停工期间工资损失','建议结合停工期间证据材料核算损失并一并主张。',1,'2026-04-07 11:41:34'),('c_labor_unpaid_additional','labor_payment','可进一步主张逾期支付加付赔偿金','欠薪在投诉/催告后仍未改正，符合加付赔偿金主张方向。','important','[\"law_contract_85\",\"law_reg_16\"]','加付赔偿金请求','具备主张基础','建议提交投诉回执、限期支付通知及逾期未支付证明材料。',1,'2026-04-07 11:41:34'),('c_labor_unpaid_core','labor_payment','欠薪请求具有较高支持可能性','已具备劳动关系、劳动提供、欠薪事实及核心证据链。','important','[\"law_labor_50\",\"law_contract_30\",\"law_contract_85\"]','欠薪支付请求','可优先主张足额支付拖欠工资','建议申请劳动仲裁并提交劳动关系、劳动提供、欠薪金额及催要记录等证据。',1,'2026-04-07 11:41:34'),('c_labor_unpaid_overtime','labor_payment','加班费请求具备基础支持条件','已明确加班请求，且有加班事实证据及计算依据。','important','[\"law_contract_30\"]','加班费请求','可一并主张','建议按工作日/休息日/法定节假日分开整理加班证据并核算金额。',1,'2026-04-07 11:41:34'),('c_labor_unpaid_term_comp','labor_contract','解除补偿请求有一定支持可能','存在欠薪，且解除原因与单位违约行为相关。','important','[\"law_contract_85\"]','解除补偿请求','可结合欠薪事实一并主张','建议保留解除前催告记录与解除通知，形成完整时间线。',1,'2026-04-07 11:41:34'),('c_marriage_annulment_arrangement','conclusion','撤销婚姻后的赔偿、财产和子女安排可并行处理','撤销后若涉及损害赔偿、财产返还或子女抚养安排，可同步设计后果处理路径。','important','[\"law_1054\",\"law_1084\"]','撤销婚姻后果路径','同步处理后果安排','分别整理赔偿、返还和抚养材料。',1,'2026-04-16 15:49:26'),('c_marriage_annulment_coercion','conclusion','撤销婚姻中的胁迫路径较明确','存在胁迫结婚事实且能说明胁迫终止时间时，撤销请求会更聚焦。','important','[\"law_1052\",\"law_1053\"]','撤销婚姻胁迫路径','优先围绕胁迫主张','提交报警、伤情、录音和时间线证据。',1,'2026-04-16 15:49:26'),('c_marriage_annulment_disease','conclusion','撤销婚姻中的重大疾病隐瞒路径较明确','婚前隐瞒重大疾病且知晓时间可说明时，撤销请求和损害赔偿都更容易成型。','important','[\"law_1053\"]','撤销婚姻重大疾病路径','优先围绕重大疾病隐瞒主张','整理病历、住院记录、婚前告知缺失材料。',1,'2026-04-16 15:49:26'),('c_marriage_annulment_exception','conclusion','撤销婚姻可能受期间限制影响','若不在法定期间内提出，或知晓时间无法说明，撤销请求风险较高。','warning','[\"law_1053\"]','撤销婚姻例外路径','需先核查时效','围绕知晓时间、胁迫终止时间补充证据。',1,'2026-04-16 15:49:26'),('c_marriage_annulment_initial','conclusion','撤销婚姻可进入原因与后果安排审查','存在撤销原因线索且有证据补强时，可组织撤销请求及撤销后财产返还/子女安排。','important','[\"law_1079\",\"law_1087\"]','撤销婚姻审查入口','建议补强胁迫/欺诈/重大疾病隐瞒的证据。','同时整理撤销后的财产与子女抚养需求证据。',1,'2026-04-16 13:45:06'),('c_marriage_annulment_precondition','conclusion','撤销婚姻纠纷已具备审查入口','存在法定撤销事由线索，且已出现撤销请求与期间判断基础。','important','[\"law_1052\",\"law_1053\"]','撤销婚姻前置','可进入实体分析','继续核查胁迫终止时间或知晓疾病时间。',1,'2026-04-16 15:49:26'),('c_marriage_annulment_support','conclusion','撤销婚姻主张存在支持路径','胁迫结婚或婚前隐瞒重大疾病的线索较明确，撤销请求具备继续主张空间。','important','[\"law_1052\",\"law_1053\"]','撤销婚姻支持路径','支持继续主张','重点固定胁迫过程、病历诊断和时间节点。',1,'2026-04-16 15:49:26'),('c_marriage_annulment_time_bar','conclusion','撤销婚姻需优先排查法定期间障碍','如无法证明在法定期间内提出，后续实体争点可能无法展开。','warning','[\"law_1053\"]','撤销婚姻期间障碍路径','需优先核查期间问题','先补知晓时间和立案时间材料。',1,'2026-04-16 15:49:26'),('c_marriage_invalid_arrangement','conclusion','婚姻无效后的财产与子女安排需同步处理','案件同时涉及财产或未成年子女安排时，应同步组织后果处理方案。','important','[\"law_1054\",\"law_1084\"]','婚姻无效后果路径','同步处理后果安排','补充财产给付、抚养现状与支出材料。',1,'2026-04-16 15:49:26'),('c_marriage_invalid_exception','conclusion','婚姻无效主张需排除错误事由混入','若仅有与他人同居等非无效法定事由线索，容易导致 /judge 答非所问。','warning','[\"law_1051\"]','婚姻无效例外路径','需校正主张方向','区分婚姻无效、撤销婚姻和离婚损害责任。',1,'2026-04-16 15:49:26'),('c_marriage_invalid_initial','conclusion','婚姻无效可进入实体确认与返还审查','无效原因线索与请求确认成立时，可组织无效确认及财产返还/安排的证据链。','important','[\"law_1079\",\"law_1087\"]','婚姻无效确认','建议补强无效原因与结婚登记/身份材料证据。','同时整理共同财产与子女抚养安排线索。',1,'2026-04-16 13:45:06'),('c_marriage_invalid_kinship','conclusion','婚姻无效中的近亲属关系路径较明确','若能证明属于禁止结婚的亲属关系，婚姻无效将围绕亲属关系认定展开。','important','[\"law_1051\"]','婚姻无效近亲路径','优先围绕亲属关系主张','重点提交户籍、出生和亲属关系材料。',1,'2026-04-16 15:49:26'),('c_marriage_invalid_precondition','conclusion','婚姻无效纠纷已具备审查入口','存在法定无效事由线索且请求主体较明确，可进入婚姻无效确认审查。','important','[\"law_1051\",\"law_1052\"]','婚姻无效前置','可进入实体分析','先锁定法定无效事由，不再混入非无效原因。',1,'2026-04-16 15:49:26'),('c_marriage_invalid_prior_marriage','conclusion','婚姻无效中的重婚路径较明确','若能证明在先婚姻未解除又再次登记结婚，婚姻无效主张更聚焦也更稳定。','important','[\"law_1051\"]','婚姻无效重婚路径','优先围绕重婚事实主张','重点提交前婚状态、登记档案和身份信息。',1,'2026-04-16 15:49:26'),('c_marriage_invalid_support','conclusion','婚姻无效确认存在支持路径','在先婚姻未解除、禁止结婚亲属关系或未达婚龄等法定事由已出现明确指向。','important','[\"law_1051\",\"law_1052\"]','婚姻无效支持路径','支持继续主张','围绕登记、身份、亲属关系和前婚状态固定证据。',1,'2026-04-16 15:49:26'),('c_marriage_invalid_underage','conclusion','婚姻无效中的未达婚龄路径较明确','若能证明登记结婚时未达法定婚龄，婚姻无效主张将围绕年龄事实展开。','important','[\"law_1051\",\"law_1054\"]','婚姻无效婚龄路径','优先围绕婚龄事实主张','重点提交身份证、户籍和登记材料。',1,'2026-04-16 15:49:26'),('c_paternity_confirmation_birth_record','conclusion','亲子确认中的出生登记与生育往来路径较明确','出生登记与确认主张一致，且存在怀孕生育期间往来和长期抚养记录时，确认路径更稳定。','important','[\"law_1073\"]','亲子确认出生登记路径','可强化确认主张','重点整理出生证明、生育往来和共同抚养记录。',1,'2026-04-16 15:49:26'),('c_paternity_confirmation_initial','conclusion','亲子确认请求具备证据补强方向','亲子争议与鉴定结论支持时，可组织亲子确认请求的证据补强。','important','[\"law_1084\"]','亲子确认审查入口','建议提交亲子鉴定结论、出生/户籍/亲属关系材料及证据清单。','如无鉴定结论，先补强鉴定可用材料。',1,'2026-04-16 13:45:06'),('c_paternity_confirmation_obstruction','conclusion','亲子确认可走举证妨碍路径','对方拒绝配合亲子鉴定或存在举证妨碍时，可强化确认主张的证明评价。','important','[\"law_81\"]','亲子确认举证妨碍路径','可强化证明评价','保留拒检、送达、调查受阻等过程材料。',1,'2026-04-16 15:49:26'),('c_paternity_confirmation_precondition','conclusion','亲子确认纠纷已具备审查入口','存在亲子关系争议且已形成确认请求或鉴定方向，可进入亲子确认审查。','important','[\"law_1073\"]','亲子确认前置','可进入实体分析','继续固定鉴定结论、出生登记和往来记录。',1,'2026-04-16 15:49:26'),('c_paternity_confirmation_support','conclusion','亲子确认存在支持路径','鉴定结论、出生登记一致性和怀孕生育期间往来记录对确认主张形成支持。','important','[\"law_1073\"]','亲子确认支持路径','支持继续主张','整理鉴定材料、出生登记和长期抚养证据。',1,'2026-04-16 15:49:26'),('c_paternity_disclaimer_birth_record','conclusion','亲子否认中的登记不一致与生活缺失路径较明确','出生登记与否认主张不一致，且共同生活或生育往来证据薄弱时，否认主张更聚焦。','important','[\"law_1073\"]','亲子否认出生登记路径','可强化否认主张','重点整理出生登记不一致和共同生活缺失材料。',1,'2026-04-16 15:49:26'),('c_paternity_disclaimer_initial','conclusion','亲子否认请求具备证据补强方向','亲子争议与鉴定结论支持否认主张时，可组织否认请求的证据补强。','important','[\"law_1084\"]','亲子否认审查入口','建议提交亲子鉴定结论、出生/户籍/亲属关系材料及证据清单。','同时整理争议形成沟通记录。',1,'2026-04-16 13:45:06'),('c_paternity_disclaimer_obstruction','conclusion','亲子否认可走举证妨碍路径','对方拒绝配合亲子鉴定或存在举证妨碍时，可强化否认主张的证明评价。','important','[\"law_81\"]','亲子否认举证妨碍路径','可强化证明评价','保留拒检、送达、调查受阻等过程材料。',1,'2026-04-16 15:49:26'),('c_paternity_disclaimer_precondition','conclusion','亲子否认纠纷已具备审查入口','存在亲子关系争议且已形成否认请求或鉴定方向，可进入亲子否认审查。','important','[\"law_1073\"]','亲子否认前置','可进入实体分析','继续固定鉴定结论、出生登记和往来记录。',1,'2026-04-16 15:49:26'),('c_paternity_disclaimer_support','conclusion','亲子否认存在支持路径','鉴定结论、出生登记不一致和怀孕生育期间往来缺失等事实可支持否认主张。','important','[\"law_1073\"]','亲子否认支持路径','支持继续主张','重点整理鉴定报告、登记不一致与生活记录缺失。',1,'2026-04-16 15:49:26'),('c_post_divorce_damage_amount','conclusion','赔偿金额与范围可进一步细化','已出现具体费用、持续治疗或误工损失线索，可细化金额计算与项目拆分。','important','[\"law_1183\",\"law_1179\"]','离婚后损害金额路径','可细化赔偿清单','将医疗费、误工费、精神损害抚慰金分别整理。',1,'2026-04-16 15:49:26'),('c_post_divorce_damage_causation','conclusion','离婚后损害的后果与因果链可继续补强','损害后果、持续治疗和误工线索存在时，可进一步强化因果关系和金额计算。','important','[\"law_1183\",\"law_1179\"]','离婚后损害因果路径','可继续补强因果链','围绕病历时间线、复诊记录和误工收入证明整理。',1,'2026-04-16 15:49:26'),('c_post_divorce_damage_exception','conclusion','离婚后损害责任可能受既判或处理完毕影响','若损害赔偿已在离婚程序中处理，或因果关系、损失范围不明确，后续主张空间会收窄。','warning','[\"law_1091\"]','离婚后损害例外路径','需先核查程序障碍','核查离婚判决、协议和既往请求处理情况。',1,'2026-04-16 15:49:26'),('c_post_divorce_damage_fault','conclusion','离婚后损害已形成明确过错识别路径','重婚、与他人同居、家庭暴力或虐待遗弃等过错类型较清晰时，更利于围绕法定过错展开主张。','important','[\"law_1091\"]','离婚后损害过错路径','过错类型较明确','围绕过错类型分别整理聊天、报警、判决或证人证言。',1,'2026-04-16 15:49:26'),('c_post_divorce_damage_liability_initial','conclusion','离婚后损害责任有证据补强空间','过错侵害事实线索与后果损害要件具备时，可形成精神损害/经济损失赔偿证成。','important','[\"law_1079\",\"law_1087\"]','损害责任审查入口','建议按“过错-后果-请求范围”补强聊天/病历/费用清单。','重点固定电子证据与损失计算依据。',1,'2026-04-16 13:45:06'),('c_post_divorce_damage_precondition','conclusion','离婚后损害责任已具备独立审查前提','离婚事实已生效且已出现过错侵害与损害后果线索，可独立进入赔偿审查。','important','[\"law_1091\",\"law_1079\"]','离婚后损害前置','可进入实体分析','继续补强过错类型、程序处理情况和因果关系。',1,'2026-04-16 15:49:26'),('c_post_divorce_damage_support','conclusion','离婚后损害责任存在支持路径','过错类型、损害后果和因果关系较明确，具备继续主张赔偿的基础。','important','[\"law_1091\",\"law_1079\"]','离婚后损害支持路径','支持继续主张','重点固定聊天、病历、报警记录及离婚阶段未处理事实。',1,'2026-04-16 15:49:26'),('c_post_divorce_property_agreement_enforce','conclusion','离婚后财产：协议履行路径较明确','离婚协议财产条款未履行且文本/催告证据充分时，可主张确认并履行。','important','[\"law_jsyi_69\",\"law_1087\"]','协议履行请求','可主张履行协议条款','建议提交协议原件、公证/登记与履行障碍证据。',1,'2026-04-16 15:56:36'),('c_post_divorce_property_conceal_penalty','conclusion','离婚后财产：隐藏转移责任路径较明确','隐藏转移线索与交易证据较充分时，可主张少分/不分或追究责任。','important','[\"law_1092\",\"law_jsyi_84\"]','责任追究请求','可主张少分/不分或返还','建议固定流水、交易对手、资产去向及时间线。',1,'2026-04-16 15:56:36'),('c_post_divorce_property_precondition','conclusion','离婚后财产：具备审查入口','离婚已生效且存在未分割/隐藏转移/协议履行争议线索，可进入再分割、责任追究或协议履行分支。','important','[\"law_1087\",\"law_jsyi_84\"]','审查入口','进入离婚后财产分支分析','建议补齐离婚文书、财产线索与交易材料。',1,'2026-04-16 15:56:36'),('c_post_divorce_property_redistribute','conclusion','离婚后财产：再分割路径较明确','存在未分割共同财产且请求方向明确时，可主张离婚后再次分割。','important','[\"law_1087\"]','再分割请求','具备再分割基础','建议整理未分割财产清单与线索来源证据。',1,'2026-04-16 15:56:36'),('c_post_divorce_property_time_limit_risk','conclusion','离婚后财产：存在发现时间/时效风险需先处理','发现时间不清或可能超过时效时，需要先补强发现节点与中断/中止线索。','warning','[\"law_jsyi_84\"]','风险提示','优先补强发现时间与时效说明','建议固定查询回执、聊天记录、线索形成过程等材料。',1,'2026-04-16 15:56:36'),('c_property_refund_defense','conclusion','存在不返还/少返还抗辩点','已登记且长期共同生活等情形下可抗辩不返还或少返还。','warning','[\"law_jshj_5\"]','抗辩返还请求','可抗辩不返还/少返还','围绕共同生活时间、过错、返还比例举证',1,'2026-04-14 16:29:27'),('c_property_refund_support','conclusion','支持主张返还彩礼/婚约财产','存在给付且满足法定返还情形，建议主张返还。','success','[\"law_jshj_5\",\"law_1042\"]','返还彩礼/婚约财产','可主张返还','围绕给付凭证、登记/共同生活、困难等举证',1,'2026-04-14 16:29:27'),('c_sibling_support_change_support','conclusion','扶养安排变更存在支持路径','已有长期照料一方且法定变更原因较明确时，可进一步主张调整扶养安排。','important','[\"law_1075\"]','扶养变更路径','可主张调整安排','补强长期照料事实及其他义务人分担情况。',1,'2026-04-16 15:49:26'),('c_sibling_support_exception','conclusion','扶养纠纷需先厘清义务人范围与能力','若义务主体、履行能力或困难程度不清，容易导致扶养请求笼统。','warning','[\"law_1075\"]','扶养纠纷例外路径','需先补强基础事实','明确多名义务人、收入水平和既往履行情况。',1,'2026-04-16 15:49:26'),('c_sibling_support_fee_support','conclusion','扶养费主张存在支持路径','生活困难、无劳动能力或重大医疗护理支出较明确时，可主张扶养费分担。','important','[\"law_1075\"]','扶养费支持路径','支持继续主张','整理亲属关系、收入能力与月扶养费测算。',1,'2026-04-16 15:49:26'),('c_sibling_support_initial','conclusion','扶养纠纷可进入扶养义务要件审查','被扶养人生活困难、扶养人能力与拒绝履行/不足时，可组织扶养费给付或变更证成。','important','[\"law_1067\"]','扶养义务审查入口','建议补强亲属关系、生活困难、收入能力与拒绝履行证据。','必要时补强变更原因属于法定情形材料。',1,'2026-04-16 13:45:06'),('c_sibling_support_medical','conclusion','扶养纠纷中的重大医疗护理支出路径较明确','存在重病、失能或长期护理支出时，扶养费请求更适合围绕医疗护理负担展开。','important','[\"law_1075\"]','扶养医疗护理路径','可围绕医疗护理支出主张','重点整理病历、护理费和费用清单。',1,'2026-04-16 15:49:26'),('c_sibling_support_multi_obligor','conclusion','扶养纠纷中的多义务人分担路径较明确','有多名扶养义务人且已存在长期照料一方时，可进一步细化分担比例和履行方式。','important','[\"law_1075\"]','扶养多义务人路径','可细化分担方案','整理成员范围、照料现状和各自收入能力。',1,'2026-04-16 15:49:26'),('c_sibling_support_precondition','conclusion','扶养纠纷已具备审查入口','已明确扶养义务关系和被扶养人困难状态，可进入扶养义务审查。','important','[\"law_1075\"]','扶养纠纷前置','可进入实体分析','继续核查医疗护理支出、多义务人和金额测算。',1,'2026-04-16 15:49:26'),('c_spousal_agreement_defense','conclusion','夫妻财产约定存在效力抗辩风险','若存在胁迫、欺诈或协议真实性不足等情形，协议效力会成为核心争点。','warning','[\"law_143\",\"law_148\"]','夫妻财产约定抗辩路径','需同步应对效力争议','核查签署过程、自由意思表示和履行行为。',1,'2026-04-16 15:49:26'),('c_spousal_agreement_performance','conclusion','夫妻财产约定的履行争议路径较明确','协议已成立但履行存在争议时，可围绕催告、支付和争议标的进一步主张履行。','important','[\"law_1065\"]','夫妻财产约定履行路径','可继续主张履行','重点整理催告记录、转账凭证和财产标的材料。',1,'2026-04-16 15:49:26'),('c_spousal_agreement_precondition','conclusion','夫妻财产约定纠纷已具备审查入口','存在夫妻财产约定协议且约定内容基本明确，可进入效力与履行审查。','important','[\"law_1065\"]','夫妻财产约定前置','可进入实体分析','继续固定书面文本、签署时间和争议财产类型。',1,'2026-04-16 15:49:26'),('c_spousal_agreement_support','conclusion','夫妻财产约定存在履行支持路径','协议文本、签署真实及履行争议较明确，具备主张有效并要求履行的空间。','important','[\"law_1065\"]','夫妻财产约定支持路径','支持继续主张','重点补强书面协议、公证登记和催告履行材料。',1,'2026-04-16 15:49:26'),('c_spousal_agreement_validity','conclusion','夫妻财产约定的成立与效力路径较明确','存在书面协议、签署时间清晰且财产范围明确时，协议效力主张更稳定。','important','[\"law_1065\"]','夫妻财产约定效力路径','可继续强化效力主张','重点整理文本、公证登记和财产范围材料。',1,'2026-04-16 15:49:26'),('c_spousal_property_agreement_initial','conclusion','夫妻财产约定纠纷可主张有效并履行（或应对无效抗辩）','协议存在、约定明确且未履行/争议履行时，可形成有效并履行的证成。','important','[\"law_1087\",\"law_1092\"]','协议有效与履行/抗辩','建议补强协议文本、公证/登记与催告履行证据。','如对方主张无效/被撤销，补强签署真实与履行证据。',1,'2026-04-16 13:45:06'),('c_support_fee_claim','conclusion','赡养费：支付请求路径较明确','生活困难事实较明确且对方拒绝履行时，赡养费支付请求更有支持度。','important','[\"law_1067\"]','赡养费请求','可主张按月/定期赡养费','建议提交生活困难、拒绝履行和收入能力材料。',1,'2026-04-16 15:56:36'),('c_support_medical_disability','conclusion','赡养纠纷：医疗/失能费用路径较明确','医疗失能、护理支出证据越充分，越利于明确赡养金额与支付方式。','important','[\"law_1067\"]','赡养费请求','可围绕医疗护理费用主张','建议汇总病历、票据、护理合同与支付凭证。',1,'2026-04-16 15:56:36'),('c_support_multi_obligor','conclusion','赡养纠纷：多名赡养人分担路径较明确','赡养人范围与各自收入能力明确时，更利于提出分担方案并落地执行。','important','[\"law_1067\"]','分担方案','可主张多名赡养人分担','建议提交赡养人清单、收入证据与既往分担记录。',1,'2026-04-16 15:56:36'),('c_support_precondition','conclusion','赡养纠纷：具备审查入口','存在赡养关系与生活困难线索，可进入赡养费、医疗护理与分担安排分支审查。','important','[\"law_1067\"]','审查入口','进入赡养纠纷分支分析','建议补齐亲属关系证明、生活困难与医疗失能材料。',1,'2026-04-16 15:56:36'),('c_visitation_child_will','conclusion','探望权中的子女意愿与既有安排路径较明确','八周岁以上子女意愿明确且既有探望频率较清晰时，更容易形成可执行探望方案。','important','[\"law_1086\"]','探望权子女意愿路径','可细化执行方案','重点整理子女意愿、既有探望频率和接送安排。',1,'2026-04-16 15:49:26'),('c_visitation_exception','conclusion','探望权可能受中止风险因素影响','若存在不利于未成年人身心健康的风险线索，探望方式和频率需要收敛设计。','warning','[\"law_1086\"]','探望权例外路径','需控制探望风险','重点核查子女意愿和中止探望风险事实。',1,'2026-04-16 15:49:26'),('c_visitation_initial','conclusion','探望权纠纷可进入明确探望安排审查','非直接抚养方存在拒绝探望/障碍且有探望请求时，可组织明确探望方式与时间的证成。','important','[\"law_1084\"]','探望权审查入口','建议补强拒绝探望证据、沟通记录与探望安排文书。','形成可执行的时间/方式/安排证据链。',1,'2026-04-16 13:45:06'),('c_visitation_precondition','conclusion','探望权纠纷已具备审查入口','已分开生活且申请方属于非直接抚养一方，可进入探望权安排审查。','important','[\"law_1086\"]','探望权前置','可进入实体分析','继续固定子女年龄、意愿和既有安排。',1,'2026-04-16 15:49:26'),('c_visitation_support','conclusion','探望权主张存在支持路径','拒绝探望、既有安排不明或需节假日住宿探望时，可进一步明确探望方案。','important','[\"law_1086\"]','探望权支持路径','支持继续主张','细化频率、接送、节假日及住宿安排。',1,'2026-04-16 15:49:26'),('c_visitation_suspension_risk','conclusion','探望权中的中止或限制风险需优先审查','存在不利于未成年人身心健康的风险线索时，探望方式和范围可能被限制。','warning','[\"law_1086\"]','探望权风险审查路径','需先控制探望风险','围绕风险事实、节假日住宿方案和保护措施整理。',1,'2026-04-16 15:49:26');
