/*!40000 ALTER TABLE `rule_law` DISABLE KEYS */;
INSERT INTO `rule_law` VALUES ('law_1042','中华人民共和国民法典','第一千零四十二条','婚姻家庭的禁止性规定','禁止包办、买卖婚姻和其他干涉婚姻自由的行为。禁止借婚姻索取财物。\n禁止重婚。禁止有配偶者与他人同居。\n禁止家庭暴力。禁止家庭成员间的虐待和遗弃。','2026-04-12 23:53:20'),('law_1062','中华人民共和国民法典','第一千零六十二条','夫妻共同财产认定','夫妻在婚姻关系存续期间所得的下列财产，为夫妻的共同财产，归夫妻共同所有：工资、奖金、劳务报酬；生产、经营、投资的收益；知识产权的收益；继承或者受赠的财产，但是本法第一千零六十三条第三项规定的除外；其他应当归共同所有的财产。','2026-03-31 17:27:25'),('law_1063','中华人民共和国民法典','第一千零六十三条','夫妻一方个人财产认定','下列财产为夫妻一方的个人财产：一方的婚前财产；一方因受到人身损害获得的赔偿或者补偿；遗嘱或者赠与合同中确定只归一方的财产；一方专用的生活用品；其他应当归一方的财产。','2026-03-31 17:27:25'),('law_1067','中华人民共和国民法典','第一千零六十七条','父母对子女的抚养义务与子女对父母的赡养义务','父母不履行抚养义务的，未成年子女或者不能独立生活的成年子女，有要求父母给付抚养费的权利。子女不履行赡养义务的，缺乏劳动能力或者生活困难的父母，有要求子女给付赡养费的权利。','2026-04-15 00:29:27'),('law_1076','中华人民共和国民法典','第一千零七十六条','协议离婚','夫妻双方自愿离婚的，应当签订书面离婚协议，并亲自到婚姻登记机关申请离婚登记。离婚协议应当载明双方自愿离婚的意思表示和对子女抚养、财产以及债务处理等事项协商一致的意见。','2026-03-31 17:27:25'),('law_1079','中华人民共和国民法典','第一千零七十九条','诉讼离婚与调解','夫妻一方要求离婚的，可以由有关组织进行调解或者直接向人民法院提起离婚诉讼。\n人民法院审理离婚案件，应当进行调解；如果感情确已破裂，调解无效的，应当准予离婚。\n有下列情形之一，调解无效的，应当准予离婚：\n（一）重婚或者与他人同居；\n（二）实施家庭暴力或者虐待、遗弃家庭成员；\n（三）有赌博、吸毒等恶习屡教不改；\n（四）因感情不和分居满二年；\n（五）其他导致夫妻感情破裂的情形。\n一方被宣告失踪，另一方提起离婚诉讼的，应当准予离婚。\n经人民法院判决不准离婚后，双方又分居满一年，一方再次提起离婚诉讼的，应当准予离婚。','2026-04-12 23:53:20'),('law_1084','中华人民共和国民法典','第一千零八十四条','离婚后的父母子女关系','父母与子女间的关系，不因父母离婚而消除。离婚后，子女无论由父或者母直接抚养，仍是父母双方的子女。\n离婚后，父母对于子女仍有抚养、教育、保护的权利和义务。\n离婚后，不满两周岁的子女，以由母亲直接抚养为原则。已满两周岁的子女，父母双方对抚养问题协议不成的，由人民法院根据双方的具体情况，按照最有利于未成年子女的原则判决。子女已满八周岁的，应当尊重其真实意愿。','2026-04-12 23:53:20'),('law_1085','中华人民共和国民法典','第一千零八十五条','离婚后子女抚养费负担','离婚后，子女由一方直接抚养的，另一方应当负担部分或者全部抚养费。','2026-04-15 00:29:27'),('law_1087','中华人民共和国民法典','第一千零八十七条','离婚时夫妻共同财产的处理','离婚时，夫妻的共同财产由双方协议处理；协议不成的，由人民法院根据财产的具体情况，按照照顾子女、女方和无过错方权益的原则判决。\n对夫或者妻在家庭土地承包经营中享有的权益等，应当依法予以保护。','2026-04-12 23:53:20'),('law_1088','中华人民共和国民法典','第一千零八十八条','家务劳动补偿','夫妻一方因抚育子女、照料老年人、协助另一方工作等负担较多义务的，离婚时有权向另一方请求补偿，另一方应当给予补偿。','2026-03-31 17:27:26'),('law_1089','中华人民共和国民法典','第一千零八十九条','离婚时夫妻共同债务清偿','离婚时，夫妻共同债务应当共同偿还。共同财产不足清偿或者财产归各自所有的，由双方协议清偿；协议不成的，由人民法院判决。','2026-04-12 23:53:22'),('law_1091','中华人民共和国民法典','第一千零九十一条','离婚损害赔偿','有下列情形之一，导致离婚的，无过错方有权请求损害赔偿：\n（一）重婚；\n（二）与他人同居；\n（三）实施家庭暴力；\n（四）虐待、遗弃家庭成员；\n（五）有其他重大过错。','2026-04-12 23:53:20'),('law_1092','中华人民共和国民法典','第一千零九十二条','侵害夫妻共同财产的法律后果','夫妻一方隐藏、转移、变卖、毁损、挥霍夫妻共同财产，或者伪造夫妻共同债务企图侵占另一方财产的，在离婚分割夫妻共同财产时，对该方可以少分或者不分。离婚后，另一方发现有上述行为的，可以向人民法院提起诉讼，请求再次分割夫妻共同财产。','2026-04-12 23:53:20'),('law_1127','中华人民共和国民法典','第一千一百二十七条','法定继承人的范围与顺序','遗产按照下列顺序继承：第一顺序：配偶、子女、父母；第二顺序：兄弟姐妹、祖父母、外祖父母。','2026-04-15 00:29:27'),('law_1130','中华人民共和国民法典','第一千一百三十条','同一顺序继承份额一般均等','同一顺序继承人继承遗产的份额，一般应当均等。','2026-04-15 00:29:27'),('law_1133','中华人民共和国民法典','第一千一百三十三条','遗嘱处分与遗嘱形式','自然人可以依照本法规定立遗嘱处分个人财产。','2026-04-15 00:29:27'),('law_contract_10','中华人民共和国劳动合同法','第十条','书面劳动合同的订立','建立劳动关系，应当订立书面劳动合同。\n已建立劳动关系，未同时订立书面劳动合同的，应当自用工之日起一个月内订立书面劳动合同。\n用人单位与劳动者在用工前订立劳动合同的，劳动关系自用工之日起建立。','2026-04-12 23:53:20'),('law_contract_14','中华人民共和国劳动合同法','第十四条','无固定期限劳动合同','无固定期限劳动合同，是指用人单位与劳动者约定无确定终止时间的劳动合同。\n用人单位与劳动者协商一致，可以订立无固定期限劳动合同。有下列情形之一，劳动者提出或者同意续订、订立劳动合同的，除劳动者提出订立固定期限劳动合同外，应当订立无固定期限劳动合同：\n（一）劳动者在该用人单位连续工作满十年的；\n（二）用人单位初次实行劳动合同制度或者国有企业改制重新订立劳动合同时，劳动者在该用人单位连续工作满十年且距法定退休年龄不足十年的；\n（三）连续订立二次固定期限劳动合同，且劳动者没有本法第三十九条和第四十条第一项、第二项规定的情形，续订劳动合同的。\n用人单位自用工之日起满一年不与劳动者订立书面劳动合同的，视为用人单位与劳动者已订立无固定期限劳动合同。','2026-04-12 23:53:20'),('law_contract_30','中华人民共和国劳动合同法','第三十条','劳动报酬的及时足额支付','用人单位应当按照劳动合同约定和国家规定，向劳动者及时足额支付劳动报酬。\n用人单位拖欠或者未足额支付劳动报酬的，劳动者可以依法向当地人民法院申请支付令，人民法院应当依法发出支付令。','2026-04-12 23:53:20'),('law_contract_31','中华人民共和国劳动合同法','第三十一条','加班与加班费','用人单位应当严格执行劳动定额标准，不得强迫或者变相强迫劳动者加班。用人单位安排加班的，应当按照国家有关规定向劳动者支付加班费。','2026-04-12 23:53:20'),('law_contract_38','中华人民共和国劳动合同法','第三十八条','劳动者可以解除劳动合同的情形','用人单位有下列情形之一的，劳动者可以解除劳动合同：\n（一）未按照劳动合同约定提供劳动保护或者劳动条件的；\n（二）未及时足额支付劳动报酬的；\n（三）未依法为劳动者缴纳社会保险费的；\n（四）用人单位的规章制度违反法律、法规的规定，损害劳动者权益的；\n（五）因本法第二十六条第一款规定的情形致使劳动合同无效的；\n（六）法律、行政法规规定劳动者可以解除劳动合同的其他情形。\n用人单位以暴力、威胁或者非法限制人身自由的手段强迫劳动者劳动的，或者用人单位违章指挥、强令冒险作业危及劳动者人身安全的，劳动者可以立即解除劳动合同，不需事先告知用人单位。','2026-04-12 23:53:22'),('law_contract_39','中华人民共和国劳动合同法','第三十九条','用人单位单方解除劳动合同（过失性辞退）','劳动者有下列情形之一的，用人单位可以解除劳动合同：\n（一）在试用期间被证明不符合录用条件的；\n（二）严重违反用人单位的规章制度的；\n（三）严重失职，营私舞弊，给用人单位造成重大损害的；\n（四）劳动者同时与其他用人单位建立劳动关系，对完成本单位的工作任务造成严重影响，或者经用人单位提出，拒不改正的；\n（五）因本法第二十六条第一款第一项规定的情形致使劳动合同无效的；\n（六）被依法追究刑事责任的。','2026-04-12 23:53:20'),('law_contract_40','中华人民共和国劳动合同法','第四十条','无过失性辞退与代通知金','有下列情形之一的，用人单位提前三十日以书面形式通知劳动者本人或者额外支付劳动者一个月工资后，可以解除劳动合同：\n（一）劳动者患病或者非因工负伤，在规定的医疗期满后不能从事原工作，也不能从事由用人单位另行安排的工作的；\n（二）劳动者不能胜任工作，经过培训或者调整工作岗位，仍不能胜任工作的；\n（三）劳动合同订立时所依据的客观情况发生重大变化，致使劳动合同无法履行，经用人单位与劳动者协商，未能就变更劳动合同内容达成协议的。','2026-04-12 23:53:20'),('law_contract_41','中华人民共和国劳动合同法','第四十一条','经济性裁员','有下列情形之一，需要裁减人员二十人以上或者裁减不足二十人但占企业职工总数百分之十以上的，用人单位提前三十日向工会或者全体职工说明情况，听取工会或者职工的意见后，裁减人员方案经向劳动行政部门报告，可以裁减人员：\n（一）依照企业破产法规定进行重整的；\n（二）生产经营发生严重困难的；\n（三）企业转产、重大技术革新或者经营方式调整，经变更劳动合同后，仍需裁减人员的；\n（四）其他因劳动合同订立时所依据的客观经济情况发生重大变化，致使劳动合同无法履行的。\n裁减人员时，应当优先留用下列人员：\n（一）与本单位订立较长期限的固定期限劳动合同的；\n（二）与本单位订立无固定期限劳动合同的；\n（三）家庭无其他就业人员，有需要扶养的老人或者未成年人的。\n用人单位依照本条第一款规定裁减人员，在六个月内重新招用人员的，应当通知被裁减的人员，并在同等条件下优先招用被裁减的人员。','2026-04-12 23:53:20'),('law_contract_46','中华人民共和国劳动合同法','第四十六条','用人单位应当向劳动者支付经济补偿的情形','有下列情形之一的，用人单位应当向劳动者支付经济补偿：\n（一）劳动者依照本法第三十八条规定解除劳动合同的；\n（二）用人单位依照本法第三十六条规定向劳动者提出解除劳动合同并与劳动者协商一致解除劳动合同的；\n（三）用人单位依照本法第四十条规定解除劳动合同的；\n（四）用人单位依照本法第四十一条第一款规定解除劳动合同的；\n（五）除用人单位维持或者提高劳动合同约定条件续订劳动合同，劳动者不同意续订的情形外，依照本法第四十四条第一项规定终止固定期限劳动合同的；\n（六）依照本法第四十四条第四项、第五项规定终止劳动合同的；\n（七）法律、行政法规规定的其他情形。','2026-04-12 23:53:22'),('law_contract_47','中华人民共和国劳动合同法','第四十七条','经济补偿的计算标准','经济补偿按劳动者在本单位工作的年限，每满一年支付一个月工资的标准向劳动者支付。六个月以上不满一年的，按一年计算；不满六个月的，向劳动者支付半个月工资的经济补偿。\n劳动者月工资高于用人单位所在直辖市、设区的市级人民政府公布的本地区上年度职工月平均工资三倍的，向其支付经济补偿的标准按职工月平均工资三倍的数额支付，向其支付经济补偿的年限最高不超过十二年。\n本条所称月工资是指劳动者在劳动合同解除或者终止前十二个月的平均工资。','2026-04-12 23:53:22'),('law_contract_48','中华人民共和国劳动合同法','第四十八条','违法解除或终止劳动合同的后果','用人单位违反本法规定解除或者终止劳动合同，劳动者要求继续履行劳动合同的，用人单位应当继续履行；劳动者不要求继续履行劳动合同或者劳动合同已经不能继续履行的，用人单位应当依照本法第八十七条规定支付赔偿金。','2026-04-12 23:53:20'),('law_contract_82','中华人民共和国劳动合同法','第八十二条','未订立书面劳动合同的二倍工资','用人单位自用工之日起超过一个月不满一年未与劳动者订立书面劳动合同的，应当向劳动者每月支付二倍的工资。\n用人单位违反本法规定不与劳动者订立无固定期限劳动合同的，自应当订立无固定期限劳动合同之日起向劳动者每月支付二倍的工资。','2026-04-12 23:53:20'),('law_contract_85','中华人民共和国劳动合同法','第八十五条','劳动报酬等逾期支付的行政处理与加付赔偿金','用人单位有下列情形之一的，由劳动行政部门责令限期支付劳动报酬、加班费或者经济补偿；劳动报酬低于当地最低工资标准的，应当支付其差额部分；逾期不支付的，责令用人单位按应付金额百分之五十以上百分之一百以下的标准向劳动者加付赔偿金：\n（一）未按照劳动合同的约定或者国家规定及时足额支付劳动者劳动报酬的；\n（二）低于当地最低工资标准支付劳动者工资的；\n（三）安排加班不支付加班费的；\n（四）解除或者终止劳动合同，未依照本法规定向劳动者支付经济补偿的。','2026-04-12 23:53:20'),('law_contract_87','中华人民共和国劳动合同法','第八十七条','违法解除或终止劳动合同的赔偿金','用人单位违反本法规定解除或者终止劳动合同的，应当依照本法第四十七条规定的经济补偿标准的二倍向劳动者支付赔偿金。','2026-04-12 23:53:20'),('law_injury_14','工伤保险条例（2010年修订）','第十四条','应当认定为工伤的情形','职工有下列情形之一的，应当认定为工伤：\n（一）在工作时间和工作场所内，因工作原因受到事故伤害的；\n（二）工作时间前后在工作场所内，从事与工作有关的预备性或者收尾性工作受到事故伤害的；\n（三）在工作时间和工作场所内，因履行工作职责受到暴力等意外伤害的；\n（四）患职业病的；\n（五）因工外出期间，由于工作原因受到伤害或者发生事故下落不明的；\n（六）在上下班途中，受到非本人主要责任的交通事故或者城市轨道交通、客运轮渡、火车事故伤害的；\n（七）法律、行政法规规定应当认定为工伤的其他情形。','2026-04-12 23:53:20'),('law_injury_17','工伤保险条例（2010年修订）','第十七条','工伤认定申请时限与责任','职工发生事故伤害或者按照职业病防治法规定被诊断、鉴定为职业病，所在单位应当自事故伤害发生之日或者被诊断、鉴定为职业病之日起30日内，向统筹地区社会保险行政部门提出工伤认定申请。遇有特殊情况，经报社会保险行政部门同意，申请时限可以适当延长。\n用人单位未按前款规定提出工伤认定申请的，工伤职工或者其近亲属、工会组织在事故伤害发生之日或者被诊断、鉴定为职业病之日起1年内，可以直接向用人单位所在地统筹地区社会保险行政部门提出工伤认定申请。\n按照本条第一款规定应当由省级社会保险行政部门进行工伤认定的事项，根据属地原则由用人单位所在地的设区的市级社会保险行政部门办理。\n用人单位未在本条第一款规定的时限内提交工伤认定申请，在此期间发生符合本条例规定的工伤待遇等有关费用由该用人单位负担。','2026-04-12 23:53:22'),('law_injury_30','工伤保险条例（2010年修订）','第三十条','工伤医疗待遇','职工因工作遭受事故伤害或者患职业病进行治疗，享受工伤医疗待遇。\n职工治疗工伤应当在签订服务协议的医疗机构就医，情况紧急时可以先到就近的医疗机构急救。\n治疗工伤所需费用符合工伤保险诊疗项目目录、工伤保险药品目录、工伤保险住院服务标准的，从工伤保险基金支付。工伤保险诊疗项目目录、工伤保险药品目录、工伤保险住院服务标准，由国务院社会保险行政部门会同国务院卫生行政部门、食品药品监督管理部门等部门规定。\n职工住院治疗工伤的伙食补助费，以及经医疗机构出具证明，报经办机构同意，工伤职工到统筹地区以外就医所需的交通、食宿费用从工伤保险基金支付，基金支付的具体标准由统筹地区人民政府规定。\n工伤职工治疗非工伤引发的疾病，不享受工伤医疗待遇，按照基本医疗保险办法处理。\n工伤职工到签订服务协议的医疗机构进行工伤康复的费用，符合规定的，从工伤保险基金支付。','2026-04-12 23:53:20'),('law_injury_33','工伤保险条例（2010年修订）','第三十三条','停工留薪期待遇','职工因工作遭受事故伤害或者患职业病需要暂停工作接受工伤医疗的，在停工留薪期内，原工资福利待遇不变，由所在单位按月支付。\n停工留薪期一般不超过12个月。伤情严重或者情况特殊，经设区的市级劳动能力鉴定委员会确认，可以适当延长，但延长不得超过12个月。工伤职工评定伤残等级后，停发原待遇，按照本章的有关规定享受伤残待遇。工伤职工在停工留薪期满后仍需治疗的，继续享受工伤医疗待遇。\n生活不能自理的工伤职工在停工留薪期需要护理的，由所在单位负责。','2026-04-12 23:53:20'),('law_injury_35','工伤保险条例（2010年修订）','第三十五条','一级至四级伤残的工伤保险待遇','职工因工致残被鉴定为一级至四级伤残的，保留劳动关系，退出工作岗位，享受以下待遇：\n（一）从工伤保险基金按伤残等级支付一次性伤残补助金，标准为：一级伤残为27个月的本人工资，二级伤残为25个月的本人工资，三级伤残为23个月的本人工资，四级伤残为21个月的本人工资；\n（二）从工伤保险基金按月支付伤残津贴，标准为：一级伤残为本人工资的90%，二级伤残为本人工资的85%，三级伤残为本人工资的80%，四级伤残为本人工资的75%。伤残津贴实际金额低于当地最低工资标准的，由工伤保险基金补足差额；\n（三）工伤职工达到退休年龄并办理退休手续后，停发伤残津贴，按照国家有关规定享受基本养老保险待遇。基本养老保险待遇低于伤残津贴的，由工伤保险基金补足差额。\n（四）由用人单位和职工个人以伤残津贴为基数，缴纳基本医疗保险费。','2026-04-12 23:53:22'),('law_injury_36','工伤保险条例（2010年修订）','第三十六条','五级至六级伤残的工伤保险待遇','职工因工致残被鉴定为五级、六级伤残的，享受以下待遇：\n（一）从工伤保险基金按伤残等级支付一次性伤残补助金，标准为：五级伤残为18个月的本人工资，六级伤残为16个月的本人工资；\n（二）保留与用人单位的劳动关系，由用人单位安排适当工作。难以安排工作的，由用人单位按月发给伤残津贴，标准为：五级伤残为本人工资的70%，六级伤残为本人工资的60%，并由用人单位按照规定为其缴纳应缴纳的各项社会保险费。伤残津贴实际金额低于当地最低工资标准的，由用人单位补足差额。\n经工伤职工本人提出，该职工可以与用人单位解除或者终止劳动关系，由工伤保险基金支付一次性工伤医疗补助金，由用人单位支付一次性伤残就业补助金。一次性工伤医疗补助金和一次性伤残就业补助金的具体标准由省、自治区、直辖市人民政府规定。','2026-04-12 23:53:22'),('law_injury_37','工伤保险条例（2010年修订）','第三十七条','七级至十级伤残的工伤保险待遇','职工因工致残被鉴定为七级至十级伤残的，享受以下待遇：\n（一）从工伤保险基金按伤残等级支付一次性伤残补助金，标准为：七级伤残为13个月的本人工资，八级伤残为11个月的本人工资，九级伤残为9个月的本人工资，十级伤残为7个月的本人工资；\n（二）劳动、聘用合同期满终止，或者职工本人提出解除劳动、聘用合同的，由工伤保险基金支付一次性工伤医疗补助金，由用人单位支付一次性伤残就业补助金。一次性工伤医疗补助金和一次性伤残就业补助金的具体标准由省、自治区、直辖市人民政府规定。','2026-04-12 23:53:20'),('law_jser_21','婚姻家庭编解释（二）','第二十一条','家务劳动补偿因素','人民法院在确定家务劳动补偿数额时，应当综合考虑一方负担家务劳动的内容和时间、双方的经济状况、当地一般生活水平等因素。','2026-03-31 17:27:26'),('law_jser_5','婚姻家庭编解释（二）','第五条','短婚赠与可撤销','婚姻关系存续期间，夫妻一方将个人所有的房屋赠与另一方或约定为共有，赠与方在赠与房产变更登记后反悔，请求分割或撤销的，人民法院应综合考虑婚姻存续时间、是否实际共同生活、离婚过错、赠与房产在双方婚姻中的作用等因素，判决赠与方是否有权撤销赠与或请求重新分割。','2026-03-31 17:27:26'),('law_jser_8','婚姻家庭编解释（二）','第八条','父母婚后出资新规','婚姻关系存续期间，一方父母全额出资为夫妻购置房屋，没有约定或者约定不明确的，原则上应认定为对夫妻双方的赠与，但父母明确表示赠与自己子女个人的除外。一方父母部分出资为夫妻购置房屋，夫妻双方以共同财产支付其余房款的，除当事人另有约定外，该房屋为夫妻共同财产，对父母的出资份额可参照相关规定处理。','2026-03-31 17:27:26'),('law_jshj_5','最高人民法院关于适用《中华人民共和国民法典》婚姻家庭编的解释（一）（法释〔2020〕22号）','第五条','彩礼返还的法定情形','当事人请求返还按照习俗给付的彩礼的，如果查明属于以下情形，人民法院应当予以支持：\n（一）双方未办理结婚登记手续；\n（二）双方办理结婚登记手续但确未共同生活；\n（三）婚前给付并导致给付人生活困难。\n适用前款第二项、第三项的规定，应当以双方离婚为条件。','2026-04-12 23:53:20'),('law_jsyi_25','婚姻家庭编解释（一）','第二十五条','婚前个人财产婚后收益','婚姻关系存续期间，一方以个人财产投资取得的收益，该收益为夫妻共同财产。','2026-03-31 17:27:26'),('law_jsyi_26','婚姻家庭编解释（一）','第二十六条','个人财产自然增值','夫妻一方个人财产在婚后产生的收益，除孳息和自然增值外，应认定为夫妻共同财产。','2026-03-31 17:27:26'),('law_jsyi_27','婚姻家庭编解释（一）','第二十七条','婚前承租公房','婚前由一方承租、婚后用共同财产购买的房屋，虽房屋权属证书登记在一方名下，但应认定为夫妻共同财产。','2026-03-31 17:27:26'),('law_jsyi_29','婚姻家庭编解释（一）','第二十九条','父母出资购房','当事人结婚前，父母为双方购置房屋出资的，该出资应当认定为对自己子女个人的赠与，但父母明确表示赠与双方的除外。当事人结婚后，父母为双方购置房屋出资的，依照约定处理；没有约定或者约定不明确的，按照民法典第一千零六十二条第一款第四项规定的原则处理。','2026-03-31 17:27:26'),('law_jsyi_32','婚姻家庭编解释（一）','第三十二条','夫妻间赠与撤销','婚前或者婚姻关系存续期间，当事人约定将一方所有的房产赠与另一方或者共有，赠与方在赠与房产变更登记之前撤销赠与，另一方请求判令继续履行的，人民法院可以按照民法典第六百五十八条的规定处理。','2026-03-31 17:27:26'),('law_jsyi_5','最高人民法院关于适用《中华人民共和国民法典》婚姻家庭编的解释（一）（法释〔2020〕22号）','第五条','彩礼返还的法定情形','当事人请求返还按照习俗给付的彩礼的，如果查明属于以下情形，人民法院应当予以支持：\n（一）双方未办理结婚登记手续；\n（二）双方办理结婚登记手续但确未共同生活；\n（三）婚前给付并导致给付人生活困难。\n适用前款第二项、第三项的规定，应当以双方离婚为条件。','2026-04-12 23:53:20'),('law_jsyi_69','最高人民法院关于适用《中华人民共和国民法典》婚姻家庭编的解释（一）（法释〔2020〕22号）','第六十九条','附协议离婚条件的财产债务处理协议效力','当事人达成的以协议离婚或者到人民法院调解离婚为条件的财产以及债务处理协议，如果双方离婚未成，一方在离婚诉讼中反悔的，人民法院应当认定该财产以及债务处理协议没有生效，并根据实际情况依照民法典第一千零八十七条和第一千零八十九条的规定判决。','2026-04-12 23:53:22'),('law_jsyi_76','婚姻家庭编解释（一）','第七十六条','房屋处置方式','双方对夫妻共同财产中的房屋价值及归属无法达成协议时，人民法院按以下情形分别处理：双方均主张房屋所有权并且同意竞价取得的，应当准许；一方主张房屋所有权的，由评估机构按市场价格对房屋作出评估，取得房屋所有权的一方应当给予另一方相应的补偿；双方均不主张房屋所有权的，根据当事人的申请拍卖、变卖房屋，就所得价款进行分割。','2026-03-31 17:27:26'),('law_jsyi_78','婚姻家庭编解释（一）','第七十八条','婚前按揭房分割','夫妻一方婚前签订不动产买卖合同，以个人财产支付首付款并在银行贷款，婚后用夫妻共同财产还贷，不动产登记于首付款支付方名下的，离婚时该不动产由双方协议处理。协议不成的，人民法院可以判决该不动产归登记一方，尚未归还的贷款为不动产登记一方的个人债务。双方婚后共同还贷支付的款项及其相对应财产增值部分，离婚时应根据民法典第一千零八十七条第一款规定的原则，由不动产登记一方对另一方进行补偿。','2026-03-31 17:27:26'),('law_jsyi_79','婚姻家庭编解释（一）','第七十九条','房改房父母名下','婚姻关系存续期间，双方用夫妻共同财产出资购买以一方父母名义参加房改的房屋，登记在一方父母名下，离婚时另一方主张按照夫妻共同财产对该房屋进行分割的，人民法院不予支持。购买该房屋时的出资，可以作为债权处理。','2026-03-31 17:27:26'),('law_jsyi_83','最高人民法院关于适用《中华人民共和国民法典》婚姻家庭编的解释（一）（法释〔2020〕22号）','第八十三条','离婚后请求分割离婚时未涉及夫妻共同财产','离婚后，一方以尚有夫妻共同财产未处理为由向人民法院起诉请求分割的，经审查该财产确属离婚时未涉及的夫妻共同财产，人民法院应当依法予以分割。','2026-04-12 23:53:20'),('law_jsyi_84','最高人民法院关于适用《中华人民共和国民法典》婚姻家庭编的解释（一）（法释〔2020〕22号）','第八十四条','依据第一千零九十二条再次分割财产的诉讼时效','当事人依据民法典第一千零九十二条的规定向人民法院提起诉讼，请求再次分割夫妻共同财产的诉讼时效期间为三年，从当事人发现之日起计算。','2026-04-12 23:53:22'),('law_labor_44','中华人民共和国劳动法','第四十四条','加班工资支付标准','有下列情形之一的，用人单位应当按照下列标准支付高于劳动者正常工作时间工资的工资报酬：\n（一）安排劳动者延长工作时间的，支付不低于工资的百分之一百五十的工资报酬；\n（二）休息日安排劳动者工作又不能安排补休的，支付不低于工资的百分之二百的工资报酬；\n（三）法定休假日安排劳动者工作的，支付不低于工资的百分之三百的工资报酬。','2026-04-12 23:53:20'),('law_labor_50','中华人民共和国劳动法','第五十条','工资应当以货币形式按月支付','工资应当以货币形式按月支付给劳动者本人。不得克扣或者无故拖欠劳动者的工资。','2026-04-12 23:53:20'),('law_labor_arbitration_2','中华人民共和国劳动争议调解仲裁法','第二条','适用范围','中华人民共和国境内的用人单位与劳动者发生的下列劳动争议，适用本法：\n（一）因确认劳动关系发生的争议；\n（二）因订立、履行、变更、解除和终止劳动合同发生的争议；\n（三）因除名、辞退和辞职、离职发生的争议；\n（四）因工作时间、休息休假、社会保险、福利、培训以及劳动保护发生的争议；\n（五）因劳动报酬、工伤医疗费、经济补偿或者赔偿金等发生的争议；\n（六）法律、法规规定的其他劳动争议。','2026-04-12 23:53:22'),('law_labor_arbitration_27','中华人民共和国劳动争议调解仲裁法','第二十七条','申请仲裁的时效','劳动争议申请仲裁的时效期间为一年。仲裁时效期间从当事人知道或者应当知道其权利被侵害之日起计算。\n前款规定的仲裁时效，因当事人一方向对方当事人主张权利，或者向有关部门请求权利救济，或者对方当事人同意履行义务而中断。从中断时起，仲裁时效期间重新计算。\n因不可抗力或者有其他正当理由，当事人不能在本条第一款规定的仲裁时效期间申请仲裁的，仲裁时效中止。从中止时效的原因消除之日起，仲裁时效期间继续计算。\n劳动关系存续期间因拖欠劳动报酬发生争议的，劳动者申请仲裁不受本条第一款规定的仲裁时效期间的限制；但是，劳动关系终止的，应当自劳动关系终止之日起一年内提出。','2026-04-12 23:53:22'),('law_labor_arbitration_5','中华人民共和国劳动争议调解仲裁法','第五条','劳动争议处理的基本方式','发生劳动争议，当事人不愿协商、协商不成或者达成和解协议后不履行的，可以向调解组织申请调解；不愿调解、调解不成或者达成调解协议后不履行的，可以向劳动争议仲裁委员会申请仲裁；对仲裁裁决不服的，除本法另有规定的外，可以向人民法院提起诉讼。','2026-04-12 23:53:22'),('law_reg_16','工资支付暂行规定（劳部发〔1994〕489号）','第十八条','劳动行政部门对克扣、无故拖欠工资等的监察处理','各级劳动行政部门有权监察用人单位工资支付的情况。用人单位有下列侵害劳动者合法权益行为的，由劳动行政部门责令其支付劳动者工资和经济补偿，并可责令其支付赔偿金：\n（一）克扣或者无故拖欠劳动者工资的；\n（二）拒不支付劳动者延长工作时间工资报酬的；\n（三）低于当地最低工资标准支付劳动者工资的。\n经济补偿和赔偿金的标准，按国家有关规定执行。','2026-04-12 23:53:20'),('law_sf_hzlj_2024_2','最高人民法院关于审理涉彩礼纠纷案件适用法律若干问题的规定（法释〔2024〕1号）','第二条','禁止借婚姻索取财物','禁止借婚姻索取财物。一方以彩礼为名借婚姻索取财物，另一方要求返还的，人民法院应予支持。','2026-04-12 23:53:20'),('law_sf_hzlj_2024_3','最高人民法院关于审理涉彩礼纠纷案件适用法律若干问题的规定（法释〔2024〕1号）','第三条','彩礼范围的认定','人民法院在审理涉彩礼纠纷案件中，可以根据一方给付财物的目的，综合考虑双方当地习俗、给付的时间和方式、财物价值、给付人及接收人等事实，认定彩礼范围。\n下列情形给付的财物，不属于彩礼：\n（一）一方在节日、生日等有特殊纪念意义时点给付的价值不大的礼物、礼金；\n（二）一方为表达或者增进感情的日常消费性支出；\n（三）其他价值不大的财物。','2026-04-12 23:53:20'),('law_sf_hzlj_2024_5','最高人民法院关于审理涉彩礼纠纷案件适用法律若干问题的规定（法释〔2024〕1号）','第五条','已结婚登记并共同生活情形下彩礼是否返还','双方已办理结婚登记且共同生活，离婚时一方请求返还按照习俗给付的彩礼的，人民法院一般不予支持。但是，如果共同生活时间较短且彩礼数额过高的，人民法院可以根据彩礼实际使用及嫁妆情况，综合考虑彩礼数额、共同生活及孕育情况、双方过错等事实，结合当地习俗，确定是否返还以及返还的具体比例。\n人民法院认定彩礼数额是否过高，应当综合考虑彩礼给付方所在地居民人均可支配收入、给付方家庭经济情况以及当地习俗等因素。','2026-04-12 23:53:20'),('law_sf_hzlj_2024_6','最高人民法院关于审理涉彩礼纠纷案件适用法律若干问题的规定（法释〔2024〕1号）','第六条','未结婚登记但已共同生活情形下彩礼是否返还','双方未办理结婚登记但已共同生活，一方请求返还按照习俗给付的彩礼的，人民法院应当根据彩礼实际使用及嫁妆情况，综合考虑共同生活及孕育情况、双方过错等事实，结合当地习俗，确定是否返还以及返还的具体比例。','2026-04-12 23:53:20');
/*!40000 ALTER TABLE `rule_law` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `rule_question`
--

DROP TABLE IF EXISTS `rule_question`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rule_question` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `questionnaire_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `group_key` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `question_key` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `answer_key` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `label` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `hint` text COLLATE utf8mb4_unicode_ci,
  `input_type` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `required` tinyint NOT NULL DEFAULT '0',
  `question_order` int NOT NULL DEFAULT '0',
  `enabled` tinyint NOT NULL DEFAULT '1',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `unit` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
