INSERT INTO `rule_question` VALUES (1,'questionnaire_divorce_property_split','G0','存在合法婚姻关系','存在合法婚姻关系','双方是否依法办理了结婚登记，存在合法婚姻关系？','须持有结婚证或可查询到有效的婚姻登记记录。','boolean',1,0,1,'2026-03-31 17:25:07',NULL),(2,'questionnaire_divorce_property_split','G0','婚姻关系已经解除或正在解除','婚姻关系已经解除或正在解除','双方是否已经离婚或正在进行离婚诉讼？','包括协议离婚（已领取离婚证）或已向法院提起离婚诉讼。','boolean',1,1,1,'2026-03-31 17:25:07',NULL),(3,'questionnaire_divorce_property_split','G0','存在房产分割争议','存在房产分割争议','双方是否就房屋的归属或价值分割存在争议？','如有一方认为房产应归自己，另一方不同意；或双方对房产价值认定不一致。','boolean',1,2,1,'2026-03-31 17:25:07',NULL),(4,'questionnaire_divorce_property_split','G1','房产购置时间','房产购置时间','该房产是在婚前还是婚后购置的？','以签订购房合同的日期为准，对比结婚登记日期。','choice',1,0,1,'2026-03-31 17:25:07',NULL),(5,'questionnaire_divorce_property_split','G1','房产出资主体','房产出资主体','房产购置的出资主体是谁？','指实际支付房款的人。','choice',1,1,1,'2026-03-31 17:25:07',NULL),(6,'questionnaire_divorce_property_split','G1','房产出资性质','房产出资性质','购房的付款方式是什么？','全款指一次性付清全部房款；按揭指支付首付后银行贷款。','choice',1,2,1,'2026-03-31 17:25:07',NULL),(7,'questionnaire_divorce_property_split','G1','产权登记主体','产权登记主体','房产证（不动产权证）上登记的是谁的名字？','以不动产权证书上记载的权利人为准。','choice',1,3,1,'2026-03-31 17:25:07',NULL),(8,'questionnaire_divorce_property_split','G1','婚后共同还贷','婚后共同还贷','婚后是否使用夫妻共同财产偿还过房贷？','夫妻共同财产包括婚后工资、奖金、经营收益等，也包括住房公积金、住房补贴。','boolean',0,4,1,'2026-03-31 17:25:07',NULL),(9,'questionnaire_divorce_property_split','G1','房产增值类型','房产增值类型','该房产在婚姻存续期间是否存在增值？增值原因是什么？','自然增值指因市场行情上涨带来的增值；投资收益指因装修翻新、出租经营等主动行为带来的增值。','choice',0,5,1,'2026-03-31 17:25:07',NULL),(10,'questionnaire_divorce_property_split','G2','签订离婚协议','签订离婚协议','双方是否签订了合法有效的离婚协议？','离婚协议需双方自愿签订，且内容不违反法律强制性规定。','boolean',0,0,1,'2026-03-31 17:25:07',NULL),(11,'questionnaire_divorce_property_split','G2','协议约定房产分割','协议约定房产分割','离婚协议中是否明确约定了房产的分割方案？','如协议中明确写明房产归谁所有、如何补偿等。','boolean',0,1,1,'2026-03-31 17:25:07',NULL),(12,'questionnaire_divorce_property_split','G2','存在房产赠与约定','存在房产赠与约定','夫妻之间是否存在房产赠与（加名/过户）的约定或承诺？','例如：一方承诺将个人名下房产加上配偶名字，或赠与给配偶。','boolean',0,2,1,'2026-03-31 17:25:07',NULL),(13,'questionnaire_divorce_property_split','G2','赠与完成过户','赠与完成过户','房产赠与是否已经完成了不动产权变更登记（过户）？','以不动产登记中心的变更登记手续是否办理完毕为准。','choice',0,3,1,'2026-03-31 17:25:07',NULL),(14,'questionnaire_divorce_property_split','G2','赠与房产认定为彩礼','赠与房产认定为彩礼','该赠与的房产是否可能被认定为彩礼性质？','判断标准：以缔结婚姻为目的、符合当地彩礼习俗、价值较大且无偿转移、在婚约缔结前后给付。','boolean',0,4,1,'2026-03-31 17:25:07',NULL),(15,'questionnaire_divorce_property_split','G2','双方已办结婚登记','双方已办结婚登记','给付彩礼后双方是否已办理了结婚登记？','仅在房产被认定为彩礼性质时需要回答。','boolean',0,5,1,'2026-03-31 17:25:07',NULL),(16,'questionnaire_divorce_property_split','G2','登记后共同生活','登记后共同生活','办理结婚登记后双方是否实际共同生活？','共同生活指双方以夫妻名义共同居住、共同承担生活开支。','boolean',0,6,1,'2026-03-31 17:25:07',NULL),(17,'questionnaire_divorce_property_split','G2','婚前给付导致生活困难','婚前给付导致生活困难','婚前给付房产（彩礼）是否导致给付方生活困难？','生活困难指依靠个人财产和离婚时分得的财产无法维持当地基本生活水平。','boolean',0,7,1,'2026-03-31 17:25:07',NULL),(18,'questionnaire_divorce_property_split','G2','存在赠与撤销法定情形','存在赠与撤销法定情形','是否存在可以撤销赠与的法定情形？','法定情形包括：受赠人严重侵害赠与人或其近亲属权益；受赠人对赠与人有扶养义务而不履行；受赠人不履行赠与合同约定的义务。','boolean',0,8,1,'2026-03-31 17:25:07',NULL),(19,'questionnaire_divorce_property_split','G3','父母出资时间','父母出资时间','父母出资购房是在子女婚前还是婚后？','以父母实际支付房款的时间为准，对比子女结婚登记日期。','choice',0,0,1,'2026-03-31 17:25:07',NULL),(20,'questionnaire_divorce_property_split','G3','父母出资比例','父母出资比例','父母出资占购房总价的比例？','全额出资指父母支付了全部房款；部分出资指父母仅支付首付或部分房款。','choice',0,1,1,'2026-03-31 17:25:07',NULL),(21,'questionnaire_divorce_property_split','G3','存在书面赠与合同','存在书面赠与合同','父母出资时是否签订了书面赠与合同？','书面赠与合同可明确赠与对象和条件。','boolean',0,2,1,'2026-03-31 17:25:07',NULL),(22,'questionnaire_divorce_property_split','G3','赠与合同归己方子女','赠与合同归己方子女','赠与合同中是否明确只归己方子女个人所有？','需要合同中有明确的文字表述，如\'赠与给我儿子/女儿个人\'。','boolean',0,3,1,'2026-03-31 17:25:07',NULL),(23,'questionnaire_divorce_property_split','G3','赠与合同赠与双方','赠与合同赠与双方','赠与合同中是否明确赠与夫妻双方？','如合同写明\'赠与给儿子和儿媳共同\'。','boolean',0,4,1,'2026-03-31 17:26:08',NULL),(24,'questionnaire_divorce_property_split','G4','婚姻存续时长','婚姻存续时长','婚姻关系存续了多长时间（月）？','从结婚登记之日起算到提起离婚之日。','number',0,0,1,'2026-03-31 17:26:08','个月'),(25,'questionnaire_divorce_property_split','G4','存在过错情形','存在过错情形','一方是否存在以下过错情形？','如有多项请选择最严重的一项。','choice',0,1,1,'2026-03-31 17:26:08',NULL),(26,'questionnaire_divorce_property_split','G4','过错有充分证据','过错有充分证据','上述过错情形是否有充分证据证明？','如报警记录、伤情鉴定、通话录音、微信聊天记录、银行转账记录等。','boolean',0,2,1,'2026-03-31 17:26:08',NULL),(27,'questionnaire_divorce_property_split','G4','主张方为无过错方','主张方为无过错方','提出房产分割主张的一方是否为无过错方？','即要求分割房产的人不是实施过错行为的人。','boolean',0,3,1,'2026-03-31 17:26:08',NULL),(28,'questionnaire_divorce_property_split','G4','存在财产处置不当行为','存在财产处置不当行为','一方是否存在隐藏、转移、变卖、毁损、挥霍夫妻共同财产或伪造债务的行为？','如私自转移房产、变卖后隐匿款项、恶意挥霍大额支出等。','boolean',0,4,1,'2026-03-31 17:26:08',NULL),(29,'questionnaire_divorce_property_split','G4','存在家务劳动超额负担','存在家务劳动超额负担','一方是否因抚育子女、照料老人、协助另一方工作等负担了较多义务？','包括全职照顾家庭、长期独自抚养子女、照顾患病老人等。','boolean',0,5,1,'2026-03-31 17:26:08',NULL),(30,'questionnaire_divorce_property_split','G4','无过错方丧失居住权','无过错方丧失居住权','无过错方是否因对方的过错行为而丧失了房产的居住权？','例如被家暴方赶出家门、无法返回共同住所等。','boolean',0,6,1,'2026-03-31 17:26:08',NULL),(31,'questionnaire_divorce_property_split','G5','婚前承租婚后购买公房','婚前承租婚后购买公房','该房产是否属于婚前由一方承租、婚后以夫妻共同财产购买的公房？','公房指单位分配的公有住房，后通过房改等方式购买产权。','boolean',0,0,1,'2026-03-31 17:26:08',NULL),(32,'questionnaire_divorce_property_split','G5','父母名义房改房','父母名义房改房','该房产是否以一方父母名义参加房改购买、登记在父母名下？','房改房指通过住房制度改革以优惠价格购买的原公有住房。','boolean',0,1,1,'2026-03-31 17:26:08',NULL),(33,'questionnaire_divorce_property_split','G6','双方对房屋价值归属无法协议','双方对房屋价值归属无法协议','双方是否无法就房屋的价值或归属达成一致意见？','如双方都想要房子，或对房屋价值认定差异很大。','boolean',0,0,1,'2026-03-31 17:26:08',NULL),(34,'questionnaire_divorce_property_split','G6','房屋处置意愿','房屋处置意愿','双方对房屋的处置意愿如何？','如果双方已达成协议则不需要回答此题。','choice',0,1,1,'2026-03-31 17:26:08',NULL),(35,'questionnaire_labor_unpaid_wages','LW0','存在劳动关系','存在劳动关系','你与单位之间是否存在劳动关系？',NULL,'boolean',1,1,1,'2026-04-07 19:21:32',NULL),(36,'questionnaire_labor_unpaid_wages','LW0','已提供劳动','已提供劳动','你是否已经实际提供劳动？',NULL,'boolean',1,2,1,'2026-04-07 19:21:32',NULL),(37,'questionnaire_labor_unpaid_wages','LW0','存在欠薪','存在欠薪','单位是否存在拖欠工资的情形？',NULL,'boolean',1,3,1,'2026-0