INSERT INTO `rule_step2_target` VALUES ('target_add_betrothal_no_refund','抗辩不予返还彩礼','通过共同生活、登记等事实抗辩不返还或少返还。',1,'2026-04-09 21:22:06'),('target_add_betrothal_refund_full','主张全额返还彩礼','围绕法定返还要件及金额证据主张全额返还。',1,'2026-04-09 21:22:06'),('target_add_betrothal_refund_partial','主张部分返还彩礼','在已共同生活或已登记情形下主张部分返还。',1,'2026-04-09 21:22:06'),('target_add_divorce_general_custody','子女抚养方案请求','围绕子女利益与抚养条件提出抚养方案。',1,'2026-04-09 21:22:06'),('target_add_divorce_general_judgment','请求判决离婚','围绕感情破裂事实请求判决离婚。',1,'2026-04-09 21:22:06'),('target_add_divorce_general_property','财产与债务处理方案','围绕共同财产、共同债务提出分割方案。',1,'2026-04-09 21:22:06'),('target_add_labor_injury_disability','主张伤残待遇','针对伤残等级主张补助金等待遇。',1,'2026-04-09 21:22:06'),('target_add_labor_injury_medical','主张工伤医疗费用待遇','围绕医疗费用及票据主张支付。',1,'2026-04-09 21:22:06'),('target_add_labor_injury_recognition','确认工伤并主张工伤待遇','围绕工伤认定与待遇项目组织请求。',1,'2026-04-09 21:22:06'),('target_add_labor_overtime_holiday','主张法定节假日加班费','围绕法定节假日加班主张法定标准加班费。',1,'2026-04-09 21:22:06'),('target_add_labor_overtime_restday','主张休息日加班费','围绕休息日加班且未补休主张加班费。',1,'2026-04-09 21:22:06'),('target_add_labor_overtime_workday','主张工作日延时加班费','围绕工作日延时加班事实与时长主张差额。',1,'2026-04-09 21:22:06'),('target_add_post_divorce_agreement_enforce','请求履行离婚协议财产条款','针对协议未履行请求确认并履行。',1,'2026-04-09 21:22:06'),('target_add_post_divorce_conceal_penalty','追究隐藏转移财产责任','针对隐藏转移财产请求少分或不分。',1,'2026-04-09 21:22:06'),('target_add_post_divorce_redistribute','离婚后再次分割财产','针对未分割财产请求再次分割。',1,'2026-04-09 21:22:06'),('target_adoption_confirm','收养确认：登记/事实与证据补强','围绕确认请求、收养登记及证据材料组织证成。',1,'2026-04-16 21:23:38'),('target_adoption_de_facto_confirm','收养确认：事实收养长期维持路径','围绕长期共同生活、照顾记录和抚养能力组织事实收养确认。',1,'2026-04-16 23:17:34'),('target_adoption_dissolve','收养解除：解除原因与证据补强','围绕解除请求、解除原因线索与证据材料组织证成。',1,'2026-04-16 21:23:38'),('target_adoption_dissolve_reason','解除收养：解除原因审查路径','围绕解除原因、不尽抚养义务或严重矛盾组织解除主张。',1,'2026-04-16 23:17:34'),('target_adoption_post_dissolve_arrangement','解除收养：解除后未成年人安排路径','围绕解除后的监护、抚养费用和生活安排组织方案。',1,'2026-04-16 23:17:34'),('target_adoption_registered_confirm','收养确认：登记收养成立路径','围绕收养登记、送养同意和主体资格组织确认收养关系。',1,'2026-04-16 23:17:34'),('target_annulment_coercion','撤销婚姻：胁迫结婚路径','围绕胁迫事实、胁迫终止时间和撤销请求组织证据。',1,'2026-04-16 23:17:34'),('target_annulment_concealed_disease','撤销婚姻：婚前隐瞒重大疾病路径','围绕重大疾病隐瞒、知晓时间和撤销请求组织证据。',1,'2026-04-16 23:17:34'),('target_annulment_effects','撤销婚姻：撤销后的财产返还与子女抚养安排','围绕撤销后需求、子女抚养安排与证据材料组织方案。',1,'2026-04-16 21:23:38'),('target_annulment_request','撤销婚姻：撤销原因与请求证成','围绕撤销原因线索、撤销请求与证据材料组织证成。',1,'2026-04-16 21:23:38'),('target_annulment_time_limit','撤销婚姻：法定期间审查路径','围绕提出时间、知晓时间和程序风险组织证据。',1,'2026-04-16 23:17:34'),('target_child_support_arrears_enforcement','抚养费：拖欠与执行/补付','围绕拖欠事实、约定/判决基础、对方支付能力固定证据。',1,'2026-04-16 23:56:30'),('target_child_support_change_amount','抚养费：变更数额（增减）','围绕抚养支出变化、收入变化、教育医疗等重大支出构建变更理由。',1,'2026-04-16 23:56:30'),('target_child_support_change_custody','主张变更抚养关系','围绕法定变更情形与有利于子女成长证据主张变更。',1,'2026-04-15 00:29:27'),('target_child_support_claim_fee','主张抚养费','围绕抚养费标准、支出与对方收入能力主张给付。',1,'2026-04-15 00:29:27'),('target_cohab_child_custody','同居子女：抚养费/抚养关系处理方案','围绕存在子女、主要抚养状况与拒绝/未支付抚养费组织方案。',1,'2026-04-16 21:23:38'),('target_cohab_contribution_ratio','同居财产：出资比例与共同购置路径','围绕共同购置房车、大额财物和一方明显高额出资组织析产方案。',1,'2026-04-16 23:17:34'),('target_cohab_direct_custody','同居子女：直接抚养与月支出路径','围绕直接抚养主张、月支出和现有照料安排组织抚养方案。',1,'2026-04-16 23:17:34'),('target_cohab_property_partition','同居财产：同居投入与析产方案','围绕同居关系、共同投入/财产范围清晰与分割争议组织证成。',1,'2026-04-16 21:23:38'),('target_common_property_split','争取认定为夫妻共同财产并依法分割','当你希望房产被纳入共同财产范围时，需重点证明婚后取得/共同出资/共同登记等事实。',1,'2026-03-31 17:27:26'),('target_divorce_custody_best_interest','离婚纠纷：子女抚养与最佳利益','围绕直接抚养、探望、抚养费与子女利益证据组织材料。',1,'2026-04-16 23:56:12'),('target_divorce_judgment_breakdown','判决离婚：感情破裂与事由链条','围绕感情破裂、分居/冲突/调解情况构建证明链条。',1,'2026-04-16 23:56:12'),('target_divorce_judgment_violence_fault','判决离婚：家暴/重大过错方向','围绕家暴或重大过错事实固定证据，强化离婚支持度及衍生请求基础。',1,'2026-04-16 23:56:12'),('target_divorce_property_debt_scope','离婚纠纷：财产与债务范围清单化','围绕共同财产/债务范围、形成时间线、证据来源整理清单。',1,'2026-04-16 23:56:12'),('target_family_partition_evidence','分家析产：财产清单/登记证据与资金来源补强','围绕财产范围清晰、不动产登记证据与清单/账本证据组织。',1,'2026-04-16 21:23:38'),('target_family_partition_member_boundary','分家析产：成员范围与分家状态路径','围绕家庭成员范围、是否已实际分家和长期占有使用状态组织析产入口。',1,'2026-04-16 23:17:34'),('target_family_partition_plan','分家析产：共同生活投入与析产请求证成','围绕共同生活/置办、共同财产范围清晰、分割争议与请求组织证成。',1,'2026-04-16 21:23:38'),('target_family_partition_registration_source','分家析产：登记名义与主要出资来源路径','围绕登记名义、主要出资来源和权属材料组织份额主张。',1,'2026-04-16 23:17:34'),('target_guardianship_assign','监护权指定/变更：能力与鉴定证据要件','围绕监护需求、无/限制能力、医学鉴定与请求指定组织证成。',1,'2026-04-16 21:23:38'),('target_guardianship_care_ability','监护权：照护能力与居住安排路径','围绕照护能力、稳定居住和日常照护安排组织监护适格性审查。',1,'2026-04-16 23:17:34'),('target_guardianship_evidence','监护权材料整合：现任监护不适合/不履行与证据补强','围绕证据材料与现任监护不适合/不履行组织反证/证成。',1,'2026-04-16 21:23:38'),('target_guardianship_subject_qualification','监护权：申请人主体资格与顺位路径','围绕申请人身份顺位、近亲属关系和基层意见组织监护资格审查。',1,'2026-04-16 23:17:34'),('target_illegal_termination_compensation','主张违法解除赔偿金','重点证明解除缺乏法定事由或程序违法，进而请求二倍赔偿。',1,'2026-04-07 19:21:32'),('target_illegal_termination_reinstatement','请求继续履行劳动合同','在违法解除情形下，优先请求恢复劳动关系并继续履行合同。',1,'2026-04-07 19:21:32'),('target_illegal_termination_revoke_decision','确认解除决定违法并撤销','确认解除决定违法，作为赔偿或恢复劳动关系前置支撑。',1,'2026-04-07 19:21:32'),('target_illegal_termination_wage_gap','主张停工期间工资损失','在解除违法且未及时恢复岗位时，主张停工待岗期间工资等损失。',1,'2026-04-07 19:21:32'),('target_in_marriage_division_conceal_transfer','婚内财产分割：藏匿/转移处理方案','围绕婚内共同财产争议、藏匿转移线索与范围清晰提出分割证成。',1,'2026-04-16 21:23:38'),('target_in_marriage_division_waste_medical','婚内财产分割：挥霍/恶意处置与医疗紧急应对','围绕挥霍/恶意处置、重大医疗支出/紧急治疗需求与范围清晰提出处置方案。',1,'2026-04-16 21:23:38'),('target_in_marriage_property_livelihood_impact','婚内财产分割：基本生活受影响与紧迫性路径','围绕重大医疗支出、挥霍处置和家庭基本生活受影响组织紧迫性论证。',1,'2026-04-16 23:17:34'),('target_in_marriage_property_type_scope','婚内财产分割：争议财产类型与范围路径','围绕争议财产类型、范围和共同财产边界组织分割主张。',1,'2026-04-16 23:17:34'),('target_inherit_confirm_share','确认继承人及份额','围绕继承顺序、份额、代位继承等确认权利。',1,'2026-04-15 00:29:27'),('target_inherit_dispute_will','遗嘱效力争议处理','围绕遗嘱形式与效力争议组织主张。',1,'2026-04-15 00:29:27'),('target_invalid_marriage_confirm','婚姻无效：确认无效与关键要件','围绕无效原因线索、确认请求与证据材料组织证成。',1,'2026-04-16 21:23:38'),('target_invalid_marriage_property_return','婚姻无效：财产返还/子女安排（证据补强）','围绕结婚登记信息与证据材料组织返还/安排论证。',1,'2026-04-16 21:23:38'),('target_invalid_prior_marriage','婚姻无效：在先婚姻未解除的无效确认路径','围绕在先婚姻未解除、登记信息和请求主体资格组织无效确认。',1,'2026-04-16 23:17:34'),('target_invalid_prohibited_kinship','婚姻无效：禁止结婚亲属关系路径','围绕亲属关系证明、登记信息和主体资格组织无效确认。',1,'2026-04-16 23:17:34'),('target_invalid_underage','婚姻无效：未达法定婚龄路径','围绕年龄事实、登记材料和主体资格组织无效确认。',1,'2026-04-16 23:17:34'),('target_labor_no_contract_double_wage','争取未签合同期间双倍工资','重点证明劳动关系成立、未签合同持续时间及工资支付事实。',1,'2026-04-07 19:21:32'),('target_labor_no_contract_open_term','请求订立无固定期限劳动合同','符合条件时请求订立无固定期限劳动合同。',1,'2026-04-07 19:21:32'),('target_labor_no_contract_sign_contract','请求补签书面劳动合同','在劳动关系持续期间，要求单位补签书面劳动合同。',1,'2026-04-07 19:21:32'),('target_labor_unpaid_wages_additional_compensation','争取逾期支付加付赔偿金','针对欠薪且经催告/责令后仍不支付的情形，主张加付赔偿金。',1,'2026-04-07 19:21:32'),('target_labor_unpaid_wages_full_payment','争取尽快足额支付欠薪','重点证成劳动关系、实际劳动及欠薪事实，并补强金额依据。',1,'2026-04-07 19:21:32'),('target_labor_unpaid_wages_overtime','一并主张加班费','在欠薪之外，主张存在加班且未依法支付加班费。',1,'2026-04-07 19:21:32'),('target_labor_unpaid_wages_termination_compensation','争取解除劳动关系并主张经济补偿','当单位长期欠薪时，考虑依法解除并主张经济补偿。',1,'2026-04-07 19:21:32'),('target_no_fault_more_share','争取无过错方获得更多份额（照顾无过错方）','当对方存在法定或重大过错且你有证据时，可主张分割时照顾无过错方权益。',1,'2026-03-31 17:27:26'),('target_paternity_confirm','亲子确认：亲子争议与鉴定支持证成','围绕确认请求、亲子争议与鉴定支持结论组织证成。',1,'2026-04-16 21:23:38'),('target_paternity_confirm_birth_record','亲子确认：出生登记一致与生育往来路径','围绕出生登记、一致性、生育往来和共同抚养记录组织证据。',1,'2026-04-16 23:17:34'),('target_paternity_confirm_evidence','亲子确认：出生/户籍/亲属关系与证据补强','围绕鉴定结论支持与证据材料组织证成补强。',1,'2026-04-16 21:23:38'),('target_paternity_confirm_obstruction','亲子确认：拒检与举证妨碍路径','围绕拒绝鉴定、调查受阻和证明妨碍行为强化确认主张。',1,'2026-04-16 23:17:34'),('target_paternity_disclaimer','亲子否认：鉴定支持否认主张与请求证成','围绕否认请求、亲子争议与鉴定支持否认结论组织证成。',1,'2026-04-16 21:23:38'),('target_paternity_disclaimer_birth_record','亲子否认：出生登记不一致与往来缺失路径','围绕出生登记不一致、生育往来和共同生活缺失组织证据。',1,'2026-04-16 23:17:34'),('target_paternity_disclaimer_evidence','亲子否认：出生/户籍/亲属关系与证据补强','围绕鉴定支持与证据材料组织证成补强。',1,'2026-04-16 21:23:38'),('target_paternity_disclaimer_obstruction','亲子否认：拒检与举证妨碍路径','围绕拒绝鉴定、调查受阻和证明妨碍行为强化否认主张。',1,'2026-04-16 23:17:34'),('target_post_divorce_agreement_validity','离婚后财产：协议效力与履行路径补强','围绕离婚协议条件、效力争议与履行证据补强。',1,'2026-04-16 23:56:30'),('target_post_divorce_damage_amount_detail','离婚后损害：赔偿项目与金额测算路径','围绕金额区间、具体费用、误工和持续治疗等项目细化请求。',1,'2026-04-16 23:17:34'),('target_post_divorce_damage_causation','离婚后损害：损害后果与因果关系路径','围绕损害后果、因果关系与后续治疗误工材料组织证据。',1,'2026-04-16 23:17:34'),('target_post_divorce_damage_economic','离婚后损害：经济损失/费用与证据链','围绕后果、可补强证据线索与具体费用/损失组织证据。',1,'2026-04-16 21:23:38'),('target_post_divorce_damage_fault','离婚后损害：过错类型与程序障碍审查','围绕过错类型、离婚程序是否处理过及独立主张空间组织证据。',1,'2026-04-16 23:17:34'),('target_post_divorce_damage_spirit','离婚后损害：精神损害/责任要件与请求范围','围绕过错侵害事实、后果损害与请求范围组织证据补强。',1,'2026-04-16 21:23:38'),('target_post_divorce_time_limit_risk','离婚后财产：发现时间与时效风险评估','围绕发现时间、线索来源与时效风险准备解释与证据。',1,'2026-04-16 23:56:30'),('target_property_no_refund','抗辩不予/少予返还','围绕登记、共同生活等事实抗辩不返还或少返还。',1,'2026-04-15 00:29:27'),('target_property_refund','主张返还彩礼/婚约财产','围绕法定返还情形、金额与证据主张返还。',1,'2026-04-15 00:29:27'),('target_sibling_support_change','扶养变更：法定情形与生活困难证成','围绕变更主张、法定情形与生活困难组织证成。',1,'2026-04-16 21:23:38'),('target_sibling_support_fee_claim','扶养费/扶养安排：扶养义务与履行不足','围绕扶养义务、生活困难、能力与拒绝履行/不足组织证成。',1,'2026-04-16 21:23:38'),('target_sibling_support_medical','扶养纠纷：重大医疗护理支出路径','围绕重大医疗护理支出、失能患病和费用分担组织扶养请求。',1,'2026-04-16 23:17:34'),('target_sibling_support_multi_obligor','扶养纠纷：多义务人与长期照料分担路径','围绕多名扶养义务人、长期照料一方和分担比例组织方案。',1,'2026-04-16 23:17:34'),('target_spousal_agreement_defense','夫妻财产约定：无效/被撤销抗辩的证据应对','围绕无效/被撤销主张、证据材料与约定明确性组织反证。',1,'2026-04-16 21:23:38'),('target_spousal_agreement_enforce','夫妻财产约定：协议有效并要求履行','围绕协议存在、约定明确性、未履行/争议与请求履行组织证成。',1,'2026-04-16 21:23:38'),('target_spousal_agreement_performance','夫妻财产约定：履行争议与催告路径','围绕未履行、争议履行和催告记录组织履行请求。',1,'2026-04-16 23:17:34'),('target_spousal_agreement_validity','夫妻财产约定：协议成立与效力路径','围绕书面协议、签署时间、财产类型和公证登记组织效力主张。',1,'2026-04-16 23:17:34'),('target_support_claim','主张赡养费/赡养安排','围绕生活困难、支出与赡养人能力主张赡养。',1,'2026-04-15 00:29:27'),('target_support_medical_disability','赡养纠纷：医疗/失能与费用链条','围绕医疗失能、护理支出与生活困难形成证明链。',1,'2026-04-16 23:56:30'),('target_support_multi_obligor_share','赡养纠纷：多名赡养人分担与支付能力','围绕赡养人范围、收入能力、分担方案组织证据。',1,'2026-04-16 23:56:30'),('target_visitation_child_will','探望权：子女年龄、意愿与既有频率路径','围绕八周岁以上子女意愿、既有探望安排和可执行性组织方案。',1,'2026-04-16 23:17:34'),('target_visitation_evidence','探望权：探望安排文书与沟通实施证据补强','围绕探望文书与实施/沟通记录组织证成补强。',1,'2026-04-16 21:23:38'),('target_visitation_fix','探望权：拒绝/障碍与明确探望请求证成','围绕非直接抚养、拒绝探望/障碍与明确探望请求组织证成。',1,'2026-04-16 21:23:38'),('target_visitation_suspension_risk','探望权：中止探望风险审查路径','围绕不利于未成年人的风险线索和探望限制方式组织审查。',1,'2026-04-16 23:17:34');
